window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q12"]=window.__LIBQ["tien-nghich"]["q12"]||{};window.__LIBQ["tien-nghich"]["q12"]["cotTruyen"]=[{"chuong":1324,"tieuDe":"Cổ Mộ Chi Địa","tomTat":"Vương Lâm hoàn thành thức tỉnh Chu Tước lần thứ tư, nghiệp chướng luân hồi cửu sắc đốt lên hư hỏa, hóa thực hỏa thành hư hỏa bộc phát kinh thiên động địa. Hắn có thể cảm nhận tâm tình trên mỗi người và biến chúng thành hư hỏa, tâm tình Vân Lạc đại ti nồng đậm hơn vô số lần. Vân Lạc đại ti nhận ra ánh mắt cửu sắc trùng với bóng lưng mơ hồ trong khoảnh khắc mình tử vong, kinh hãi tột độ. Lam Mộng đạo tôn phát hiện Nguyệt Nhi nhìn Vương Lâm, lần đầu hối hận vì năm đó đã xóa ký ức Nguyệt Nhi thay vì giữ Vương Lâm lại. Lão Chu Tước vui mừng ném Viêm Long trả tự do, nhưng thực chất truyền âm hứa dạy Vương Lâm phương pháp cấm chế nó. Vương Lâm bước vào Thiên phương giới — khảo nghiệm tiềm lực cuối cùng do Điên Lạc đại đế trấn giữ, xuất hiện trên bàn tay pho tượng khổng lồ. Tại nơi khác trong Thái Cổ Tinh Thần, u quang hủy diệt tinh cầu hoang dã, khe nứt trăm trượng tỏa tử khí mở ra — bên trong tràn đầu lâu Cổ Thần, Cổ Ma, Cổ Yêu: Cổ Mộ đã mở."},{"chuong":1325,"tieuDe":"Tam Đại Nghiệt Tước","tomTat":"Vương Lâm vào Thiên Phương giới, đối diện pho tượng khổng lồ của Lão Tổ Chu Tước đời đầu tiên, tự xưng Chu Tước đời thứ sáu. Lão tổ bừng tỉnh, khen huyết mạch ít mà tỉnh giấc bốn lần, đề ra thí luyện: mỗi năm nhịp thở kiên trì trong Chu Tước Sâm La Viêm thì được hỏi một câu. Cùng lúc, cổ mộ trong Thái Cổ Tinh Thần mở ra tạo dòng xoáy kinh thiên, hút phế tinh hủy diệt sinh linh. Bản thể Diệu Âm đạo tôn ở đáy biển sâu bừng mắt, lệnh phân thân bước thứ ba trên Đại Đế tinh bỏ lễ mau về tra xét. Lão già mặt âm dương cùng Vọng Nguyệt cũng lao thẳng tới cổ mộ. Trên Đại Đế tinh, Lam Mộng đạo tôn đưa Lý Thiến Mai rời đi, lão già miệng bị châm xuyên cưỡi thằn lằn bay đi. Vương Lâm bị Sâm La Viêm thiêu đốt cực khốc liệt, vượt năm nhịp thở thì thân thể bên ngoài vỡ tan, hỏi về nguồn gốc Hỏa Tước tộc và biết Nghiệt Tước đời thứ ba trộm chí bảo lập thành Hỏa Tước tộc. Tới sáu nhịp thở đạt cực hạn, Vương Lâm triệu lôi đồ từ mắt phải lấy lôi kháng hỏa, cuối cùng vượt được mười nhịp thở."},{"chuong":1326,"tieuDe":"Tu Hành Như Chưởng","tomTat":"Vương Lâm tiếp tục chịu thí luyện trong Thiên phương giới, dùng lôi đồ và lửa Chu Tước chống lại Chu Tước già nua do pho tượng biến hóa, hồn phách nổ tung một nửa, thân thể bên ngoài Đại đế tinh phun máu. Hắn rút huyết kiếm và lần đầu mở Cổ Lôi Giới triệu hoán thái cổ Lôi Long, nhưng bị Chu Tước đời đầu dùng Chu Tước ấn phong bế hoàn toàn. Huyết kiếm tấn công pho tượng bị chặn, nhưng khiến Chu Tước đời đầu lần đầu lộ vẻ khiếp sợ. Lão Chu Tước xông vào can thiệp nhưng bị đẩy thần thức văng ra. Từ nhịp thở 15 đến 19, bàn tay pho tượng nắm lại bóp nát thân thể Vương Lâm, hồn phách hóa Chu Tước. Chu Tước đời đầu dùng hư hỏa chín màu thẩm tra toàn bộ quá khứ, xác nhận ấn ký Chu Tước đời thứ năm trên mi tâm Vương Lâm, rồi thở dài buông tay. Lão thú nhận đã sắp xếp mọi thứ từ tu chân tinh Long Giáp tộc để xác minh Vương Lâm, vì năm xưa bị Chu Tước đời thứ ba — kẻ do người khác tạo ra — lừa gạt dẫn tới bị nhốt trong Thiên phương giới. Cuối cùng giảng đạo: chỉ ra Vương Lâm có năm bổn nguyên nhưng con đường sai, phá không ngũ chỉ chính là thiên nhân ngũ suy, tu hành như bàn tay — năm ngón tay phải đầy đủ mới phá không."},{"chuong":1327,"tieuDe":"Cũng Có Thể","tomTat":"Chu Tước đời đầu tiên giảng giải cho Vương Lâm bản chất Phá Không Ngũ Chỉ và con đường Niết Không bước thứ ba, chỉ ra rằng thân thể Cổ Thần kết hợp năm đạo bổn nguyên khiến việc tiến vào Niết Không cực kỳ khó khăn. Lão đề xuất Vương Lâm từ bỏ thân Cổ Thần và bốn bổn nguyên, chỉ giữ hỏa bổn nguyên, ở lại Thiên Phương giới trăm năm để lão trợ giúp bước vào bước thứ ba rồi truyền Sâm La Viêm, sau đó cùng rời đi trở lại thế giới của lão. Lão lộ tâm trạng mệt mỏi, muốn về nhà, không muốn tham gia tranh đấu nữa. Vương Lâm bị đề xuất hấp dẫn mạnh, dao động kịch liệt, xin thêm vị trí cho bằng hữu và lấy quan tài Lý Mộ Uyển ra hỏi cách cứu sống. Chu Tước đời đầu phân tích tình trạng Lý Mộ Uyển: thọ nguyên tuyệt, Nguyên Anh tử vong, hồn phách tan nát, quan tài giữ linh hồn tạm; tại quê nhà lão có ba người có thể cứu nàng nhưng đều hạng cao quý khó nhờ. Vương Lâm nhớ tới Lý Mộ Uyển, Tư Đồ Nam, Thanh Thủy, Chu Như, Lý Thiến Mai, nhận ra không thể bỏ rơi ai và không thể giao sinh tử người thân vào tay kẻ khác. Hắn kiên quyết từ chối đề xuất, tuyên bố bọn họ tu tới trình độ như thế thì Vương Lâm cũng có thể, tự ngộ con đường riêng: năm đạo bổn nguyên chính là năm ngón tay, khi đại thành sẽ phá không môn thành đạo. Ba chữ Cũng có thể vang động thiên địa, Chu Tước đời đầu tiên sững sờ."},{"chuong":1328,"tieuDe":"Tới Đây","tomTat":"Vương Lâm vái pho tượng Chu Tước đời đầu tiên, thu Huyết kiếm trở lại và tuyên thệ trước thiên địa rằng sẽ chỉ dựa vào sức bản thân để cứu Uyển Nhi sống lại, tự đánh tan thiên không rồi mang tất cả bằng hữu thăng tiên. Chu Tước đời đầu trầm mặc rồi thừa nhận Vương Lâm có thể đúng, xác nhận hắn đã vượt qua thí luyện Thiên phương giới, cảnh báo chi tiết về Nghiệt tước đời thứ ba — kẻ gian trá có thiên tư đệ nhất, bị đánh trọng thương nhưng còn đường lui, nghi có thân phận khác ở Thái Cổ Tinh Thần, có thể đang bế quan thánh địa Hỏa Tước tộc. Lão tặng Vương Lâm lông chim chín màu ngưng tụ Sâm La Hỏa để phòng thân, truyền khẩu quyết điều khiển chí bảo Chu Tước tộc đang trong tay Nghiệt tước, dặn lưu lại tộc nhân Hỏa Tước tộc vì còn tác dụng lớn, rồi pho tượng mất sinh cơ. Bên ngoài, Thiên phương hương bùng cháy mãnh liệt rồi cháy sạch, tu sĩ bốn phía cho rằng Vương Lâm thất bại, nhưng đúng khoảnh khắc cuối hồn phách hắn trở về thân thể, thương thế khôi phục và hồn phách ngưng tụ hơn trước. Vương Lâm xuất hiện trong ngọn lửa, mắt trái có lửa chín màu, mắt phải có lôi đồ chín luồng lôi điện, ánh mắt khiến mấy vạn tu sĩ cảm giác bị thiêu đốt. Hắn vung tay hút hư hỏa từ cơ thể mấy vạn tu sĩ, tạo cơn lốc hư hỏa khổng lồ — được Lão Chu Tước kinh hãi xác nhận là ngưng tụ hư hỏa bên ngoài. Vân Lạc đại ti tái mặt vì cảnh tượng giống hệt hư ảo nàng từng thấy. Vương Lâm từ trong cơn lốc nhìn xuống, thách đấu Tư Mặc Tử."},{"chuong":1329,"tieuDe":"Chiến!","tomTat":"Vương Lâm công khai khiêu chiến Ti Mặc Tử (bước thứ ba, Không Niết Sơ kỳ) trước mấy vạn tu sĩ trên Đại Đế tinh, khiến tất cả chấn động. Ti Mặc Tử nghiêm túc ra tay, tuần tự thi triển đại thần thông Phá Không Cửu Diệt — chín bước chín diệt từ thiên đến phá thiên — hợp nhất thành chưởng cửu bộ diệt thiên. Vương Lâm kích phát cửu sắc hư hỏa, niệm chú hóa cơn lốc thành chín con viêm long chín màu, dùng song chỉ hóa kiếm tập hợp chín rồng đối kháng chưởng Phá Thiên. Hai lực va chạm kịch liệt, gần một vạn tu sĩ xung quanh phun máu thụ thương. Vương Lâm bị đẩy lùi trăm trượng nhưng hư hỏa không bị dập tắt, trong khi Ti Mặc Tử lộ ra vẻ khiếp sợ vì Phá Thiên ấn bất lực trước ngọn lửa. Lão Chu Tước cười đắc ý, tiết lộ vài cái tát trước đó dành cho Ti Mặc Tử cũng không nhẹ. Vân Lạc tâm thần chấn động, hình ảnh Vương Lâm và thân ảnh đáng sợ trong bức họa xen lẫn trong tâm trí nàng. Vương Lâm nắm khoảnh khắc Ti Mặc Tử lộ sợ hãi, lập tức phản công hô Hư hỏa bốc lên."},{"chuong":1330,"tieuDe":"Hương Hỏa Nhất Bái!","tomTat":"Lão Chu Tước tiết lộ ba cái tát trước đó đã cài hư hỏa trong thân Tư Mặc Tử, khiến hắn bị tâm tình dao động và hư hỏa bùng phát từ bên trong. Vương Lâm nén thương thế, phóng hư hỏa chín màu từ đồng tử đồng thời tạo cuồng phong kích phát tâm tình mấy vạn tu sĩ quan chiến, rút hư hỏa từ cơ thể họ ngưng tụ thành 36.793 con viêm long — điều mà Chu Tước đời thứ tư và đời thứ hai không thể làm, vì hư hỏa Vương Lâm có nguồn từ lực Thiên Nghịch. Vương Lâm lần lượt rút ngọc bội Phá Thiên Tông và khối thú cốt để công tâm Tư Mặc Tử, hỏi thẳng tên thật Tư Mã Mặc khiến hắn phun máu. Tư Mặc Tử xé không gian mở hương hỏa giới — giới riêng chứa vô số tu chân tinh với sinh linh cúng bái — triệu vô tận hồn phách hương hỏa, thi triển hương hỏa thần thông dập tắt hư hỏa trên người rồi sai hồn phách vái Vương Lâm một cái, cuồng phong tím kèm quy tắc bước thứ ba áp bức hắn đau đớn gần xé thân. Giữa tử quang, ở mi tâm Tư Mặc Tử xuất hiện thân hình nhỏ bé — tàn dư linh hồn gốc Tư Mã Mặc — ngồi khoanh chân nước mắt chảy kêu cầu cứu. Lão Chu Tước định ra tay nhưng Vương Lâm quyết tự mình đối mặt, hô lớn ngăn lão tổ lại."},{"chuong":1331,"tieuDe":"Phong Hương Hỏa Giới!","tomTat":"Tư Mặc Tử triệu hồi hồn phách hương hỏa vô tận từ hương hỏa giới phía sau, ép Vương Lâm rỉ máu lùi bước. Vương Lâm bùng chiến ý, lấy Cổ Tức Diệp — bảo vật Tham Lang thu từ vùng đất cổ mộ — phun máu Cổ Thần kích phát, chiếc lá phát hồng quang vạn trượng xuyên qua thân Tư Mặc Tử dán lên khe hương hỏa giới, phong ấn thành công nguồn hồn phách, tạo tiền lệ chưa từng có. Vân Lạc kinh hãi nhớ lại bức họa: tiền thân Vương Lâm từng dùng 99 chiếc lá tương tự phong ấn trời đất, phong ấn nhiều tu sĩ Thái Cổ tinh thần bằng tuyệt thế đạo thuật. Vương Lâm triệu Cổ Ma Hồn từ ngực ra chiến, Cổ Ma Hồn hóa hình người nhỏ bé triệu trường thương hư thực tấn công. Tư Mặc Tử dù đau đớn vẫn thi triển Tử Đạo — đạo bổn nguyên màu tím do Chưởng Tôn ban cho — sương tím lan tràn khiến linh hồn phát điên. Nhưng Cổ Ma Hồn thân là Cổ Ma đứng đầu ma trong trời đất, không sợ mà hưng phấn nuốt sương tím, ma tính càng dày, xuyên qua màn sương lao thẳng đến Tư Mặc Tử."},{"chuong":1332,"tieuDe":"Nhân Tài!","tomTat":"Vương Lâm triệu xuất Thiên Hoàng Lô — pháp khí vương tộc Cổ Thần — bao vây Tư Mặc Tử vào bên trong lò, phun ba ngụm máu tươi dùng ba chữ Định khống chế rồi ngồi lên đỉnh lò dùng lôi hỏa giao hòa luyện hóa. Sự kiện chấn động tu sĩ bốn phía vì từ cổ chí kim chưa ai luyện hóa cao thủ bước thứ ba. Lão Chu Tước trợn mắt kinh ngạc, tiết lộ đã âm thầm dọa nạt Tư Mặc Tử khiến hắn không dám xuất sát chiêu, khen Vương Lâm là nhân tài. Tư Mặc Tử phản kháng dữ dội, triệu nữ tử lụa trắng từ dải lụa vết máu hoa mai phóng sức mạnh tuế nguyệt, rồi dùng 29 Thất Thải Thần Không Đinh đâm xuyên vách lò. Vương Lâm rút Ma Hồn Bình phun máu Cổ Thần triệu ba vạn Cổ Ma trợ giúp luyện hóa. Tư Mặc Tử lấy bộ xương thú có chưởng ấn Chưởng Tôn định phá lò, nhưng nữ tử lụa trắng u uất van xin đưa muội về nhà khiến hắn dừng tay. Cuối chương Vương Lâm thi triển Mộng Đạo — đệ nhất đạo thuật cả đời, sáng chế bên trong Đạo Cảnh ở Thiên Nghịch, sau Tàn Dạ và Lưu Nguyệt."},{"chuong":1333,"tieuDe":"Mộng Đạo Chủng Ma","tomTat":"Vương Lâm hồi tưởng ba thức thần thông tự sáng tạo trong hai ngàn năm tu đạo: Tàn Dạ (quy tắc ban đầu, uy lực khi đêm tàn), Nguyệt Lưu (quy tắc Tuế Nguyệt, không ai phòng ngự nổi), và Mộng Đạo — thức thứ ba sáng chế trong Đạo Cảnh bằng cách dung hợp Mộng Về Viễn Cổ và Tán Đạo. Mộng Đạo thuật có bản chất ma hóa tâm ma trong đạo niệm đối phương, tạo ký ức hư ảo vĩnh hằng không thể loại bỏ để phá tan đạo tâm. Vương Lâm thi triển Mộng Đạo, thổi đạo tức vào Thiên Hoàng Lô gieo tâm ma vào Tư Mặc Tử. Tư Mặc Tử nhìn thấy hư ảnh muội muội tự vẫn mặc áo trắng vấy máu, sững sờ run rẩy, quên mất thú cốt và chưởng ấn trên tay. Ký ức hư ảo tái hiện cuộc đời Tư Mã Mặc — thiếu niên phàm nhân mồ côi cùng muội muội Tiểu Lan, mộng trở thành tiên nhân. Ngày đại hôn của Tiểu Lan, mười một đại hán cưỡi ngựa xông vào thôn trang, lửa cháy ngập trời."},{"chuong":1334,"tieuDe":"Có Lẽ Sẽ Có Một Ngày","tomTat":"Vương Lâm thâm nhập ký ức Tư Mặc Tử qua Dục Tiên Dục Tử trong Thiên Hoàng Lô, chứng kiến trọn quá khứ bi thảm của hắn. Thuở nhỏ Tư Mã Mặc là thiếu niên hái thuốc, đám mã phỉ tàn sát thôn trang, muội muội Tiểu Lan bị lăng nhục rồi tự vẫn bằng dải lụa trắng. Hắn chôn cất muội muội trên đỉnh núi có hoa lan tím, giữ dải lụa trong ngực cảm nhận hồn phách nàng vẫn lưu bên trong. Nhập Phá Thiên Tông, đạt Nguyên Anh, truy sát hơn 1400 tên mã phỉ trong một đêm mưa gió, thậm chí dùng thần thông tính ra kiếp chuyển thế của kẻ thù đã chết để giết tiếp. Sau bị đuổi khỏi Phá Thiên Tông, trong Thất Thải Giới bị đóng Thất Thải Đinh, cứng cỏi từ chối đầu hàng giới ngoại nhưng Chưởng Tôn dụ bằng lời hứa cho muội muội ngưng hóa thành hình và có thể sống lại, hắn cuối cùng đi theo đổi tên thành Tư Mặc Tử. Trở về hiện tại, Vương Lâm mở mắt phá tan Thiên Hoàng Lô, bỏ qua luyện hóa Tư Mặc Tử vì nhận định tiếp tục cũng không thành công. Tư Mặc Tử thu hư ảnh muội muội vào tay áo, hỏi Vương Lâm lời nói của muội ấy là pháp thuật hay thật, Vương Lâm đáp không biết. Cuối chương Vương Lâm tự hỏi nếu muội muội kia là Uyển Nhi thì sẽ lựa chọn ra sao, hoặc từ Tư Mặc Tử đã có đáp án rồi."},{"chuong":1335,"tieuDe":"Chia Tay","tomTat":"Sau trận chiến trên Đại đế tinh, uy danh Vương Lâm quật khởi, được mấy vạn tu sĩ công nhận có thể giao chiến với cao thủ bước thứ ba. Trong vùng đất Điên Lạc, Lưu Kim Bưu bị Hỏa Tước tộc bắt giữ và đưa ra ngoài gặp lão tổ. Lưu Kim Bưu giả dạng Chu Tước đời thứ sáu đang bế quan chữa thương, vượt qua mọi kiểm tra của lão tổ Hỏa Tước tộc bao gồm rút tiên huyết và Sưu Hồn Thuật quét ký ức, khiến lão tổ hoàn toàn tin tưởng rồi cuốn hắn về tổng bộ. Vương Lâm ngồi bên hồ cạnh Lão Chu Tước, khen đạo thuật Lưu Kim Bưu cao minh, đồng thời bấm quyết tạo Truyền Tống trận quanh thân thể, chuẩn bị khi Lưu Kim Bưu vào thánh địa Hỏa Tước tộc thì xuyên qua xâm nhập. Trước khi chia tay, Lão Chu Tước tách cấm chế Cổ Hồn Cấm thành mai rùa phát u quang giao cho Vương Lâm phòng thân tự nghiên cứu, đồng thời giao nhiệm vụ dùng ấn ký Chu Tước tuyển chọn Chu Tước đời thứ bảy với yêu cầu nghiêm ngặt phải bảo tồn nguyên dương hoàn hảo. Đổi lại, Lão Chu Tước hứa truyền cho Vương Lâm một trong ba thuật mạnh nhất của Chu Tước tộc do Viễn Cổ tiên tôn truyền lại, là thần thông bảo mệnh uy lực cực lớn nhưng phải thiêu đốt tuổi thọ khi sử dụng."},{"chuong":1336,"tieuDe":"Quyết Tâm!","tomTat":"Lão Chu Tước bắt đầu truyền thụ thần thông mạnh nhất Chu Tước tộc — Phần Giới Cổ Tán — cho Vương Lâm. Hắn biểu diễn bốn lần ấn quyết tổng gần hai trăm vạn ấn ký trong chín nhịp thở, hình thành cơn lốc hỏa cốt dạng cái ô chưa mở với vô số hỏa long vờn quanh, uy áp kinh thiên trùm Đại đế tinh và lan ra nửa vùng Điên Lạc. Lão Chu Tước giải thích thuật do Viễn Cổ Tiên Hoàng học trộm mà thành, không hoàn chỉnh — Tiên Hoàng năm xưa mở ô tám lần diệt vạn người một giới, lão tổ đời thứ nhất Chu Tước tộc đạt Không Kiếp sơ kỳ chỉ mở năm lần, còn bản thân Lão Chu Tước nhờ nguyên dương chưa bị phá nên mở được hai lần. Sau khi phun máu thu hồi cơn lốc, Lão Chu Tước trao ngọc giản chứa toàn bộ ấn quyết cho Vương Lâm rồi khoanh chân thổ nạp hồi phục. Vương Lâm chấn động trước sức mạnh vượt tầm tưởng tượng, suy tư về kẻ sáng tạo thuật gốc và thế giới ngoài bầu trời, kích phát bất cam trong tính cách — tự nhủ hôm nay học thuật của người, ngày khác sẽ khiến người phải học thuật của Vương Lâm. Hắn dung nhập tâm thần vào ngọc giản khắc sâu mọi ấn quyết rồi hủy ngọc giản thành tro bụi bay về phía chân trời."},{"chuong":1337,"tieuDe":"Ý Tưởng Điên Cuồng","tomTat":"Lão tổ Hỏa Tước tộc (bước thứ ba, Không Niết sơ kỳ) thi triển Súc Địa Thành Thốn mang Lưu Kim Bưu đóng giả Chu Tước đời thứ sáu về thánh địa trên Hỏa Tước tinh. Trong biển lửa thánh địa có cánh cửa hư ảo dẫn vào vùng tinh không chứa ngọn lửa bảy màu khổng lồ, nơi một thân ảnh bí ẩn bế quan trị thương — lão tổ bước thứ ba quỳ gối gọi người này là chủ nhân. Thân ảnh bí ẩn nhận ra Lưu Kim Bưu không phải Chu Tước đời thứ sáu, dùng sợi tơ rút máu và sức sống của hắn. Lưu Kim Bưu nguy cấp phun tinh khí, Hứa Lập Quốc xuất hiện biến thành đại kiếm tạo lốc kiếm, tuyên bố thông đạo đã mở — đây chính là mục đích Vương Lâm sắp đặt từ trước. Trên Đại đế tinh, Vương Lâm đang tìm hồn phách Thiên Vận Tử trong Hô Phong Hoán Vũ giới thì đột nhiên mở mắt, suy luận chín phần chính xác rằng thân ảnh bí ẩn chính là tam đại nghiệt tước, đã âm thầm thao túng Thái Cổ Tinh Thần suốt vài ngàn năm: con gái hắn dụ dỗ Thanh Lâm, hủy hương hỏa Tứ Đại Tiên giới, bức bách chủ nhân Phong Giới, nghi ngờ liên quan việc Thanh Thủy điên khùng. Vương Lâm nảy ý tưởng điên cuồng tấn công đối phương lúc trị thương, kích hoạt trận pháp biến mất. Bên hồ, Lão Chu Tước (Chu Tước đời thứ 14) trái ý lão tổ đời đầu, tự tiện truyền thuật mạnh nhất Chu Tước tộc cho Vương Lâm vì tin hắn xứng đáng sau thí luyện."},{"chuong":1338,"tieuDe":"Mò Trăng Đáy Giếng","tomTat":"Trong thánh địa Hỏa Tước tộc, Hứa Lập Quốc hoảng sợ cầu cứu khi Lưu Kim Bưu bị vô số xúc tu quấn chặt. Vương Lâm xé toạc cơn lốc kiếm bước vào, dùng lôi đình kết hợp lửa chín màu cứu cả hai đưa vào không gian trữ vật. Chưởng Tôn nhận ra Vương Lâm, cảm nhận khí tức Thanh Lâm, Thanh Thủy, Tư Mã Mặc trên người hắn, phán đoán hắn dám tới vì biết Chưởng Tôn trọng thương. Vương Lâm tổng lực tấn công bằng lửa chín màu, chín con Thái Cổ Lôi Long, Vạn Cổ Mộc Linh và huyết kiếm, nhưng Chưởng Tôn thi triển đại thần thông Mò Trăng Đáy Giếng — biến tinh không thành mặt nước hình giếng, phản chiếu rồi mò hồn Vương Lâm lên bóp nát. Tuy nhiên thứ bị mò là Cổ Ma Hồn đã xóa thần trí thế chỗ hồn phách — kế hiểm chỉ Cổ Thần đồng nguyên Cổ Ma mới làm được. Vương Lâm tổn thương nhưng sống, rút lông Chu Tước hóa biển lửa bao trùm bầu trời, tự xưng Chu Tước đời thứ sáu, đọc khẩu quyết Trạch Lưu Tước Vũ triệu nguyên linh Chu Tước tộc từ Thái Cổ Giới giáng lâm. Chưởng Tôn lộ diện là nam tử trung niên mặc áo giáp xám gắn liền thân thể, thừa nhận đã xem thường Vương Lâm. Chương cũng tiết lộ Vương Lâm trước đó đã dung hợp hồn Thiên Vân Tử để triển khai kế hoạch điên cuồng và chuẩn bị đường lui chu toàn."},{"chuong":1339,"tieuDe":"Mở Ô Diệt Thế","tomTat":"Vương Lâm lấy chiếc lông chí bảo do Chu Tước đời thứ nhất ban tặng triệu hồi nguyên linh Chu Tước chân chính — con Chu Tước khổng lồ chiếm hơn nửa bầu trời giáng xuống, uy áp ngang bát tinh Cổ Thần trưởng thành. Chưởng Tôn hóa ngọn lửa bảy màu thành hình Chu Tước đối kháng nhưng vỡ tan, phun máu rồi thi triển Tứ Đại Giai Không Thuật triệu xuất bốn tầng nguyên tố Địa Thủy Hỏa Phong xếp chồng lao lên. Qua bốn nhịp thở va chạm, cả bốn tầng đều tan vỡ trước nguyên linh Chu Tước, lực xung kích quét ngang khiến tinh không xé rách và thánh địa Hỏa Tước tộc bắt đầu sụp đổ, cả hai đều phun máu bị thương. Vương Lâm nhận định có thể rút về giới nội nhưng quyết không bỏ qua cơ hội giết Chưởng Tôn, muốn làm việc kinh thiên khiến cả Thái Cổ chấn kinh. Hắn nhận ra lão tổ đời thứ hai đã truyền Phần Giới Cổ Tán chính là để trợ giúp lúc này. Trong chín nhịp thở đánh ra gần hai trăm vạn ấn ký hình thành Phần Giới Cổ Tán khổng lồ, sức sống bị Cổ Tán hấp thụ, miệng tràn máu. Chưởng Tôn bước tới định giết, vung chưởng ấn xuyên thấu vạn cổ mộc linh mà Vương Lâm phóng ra cản đường. Vương Lâm gầm lên Mở ô diệt thế vung hai tay thi triển, chương kết thúc ở đỉnh cao."},{"chuong":1340,"tieuDe":"Ngày Này Đã Tới!","tomTat":"Vương Lâm nhỏ máu kích hoạt Phần Giới Cổ Tán, hỏa khí vô hình phá vỡ chưởng ấn Chưởng Tôn nhưng tu vi chưa đủ chỉ mở được hai phần. Chưởng Tôn xé tấm áo giáp thái cổ chí bảo (lấy từ sư tôn) biến thành bàn tay khổng lồ đối kháng. Vương Lâm quát cho Cổ Tán tự hủy nổ tung, sức mạnh hủy diệt phá sập toàn bộ thánh địa Hỏa Tước tộc, lão tổ Hỏa Tước tộc ngồi ngoài cửa bị mảnh vỡ đánh trọng thương. Vương Lâm thoát ra ngoài nhưng bị Chưởng Tôn truy kích, liên tiếp dùng Hô Phong Hoán Vũ giới, Quang Ảnh thuẫn, Thiên Hoàng Lô, Cổ Thần hộ tí phòng ngự đều bị phá, bị đánh xuyên qua tu chân tinh sụp đổ rơi vào tinh không Thái Cổ Tinh Thần. Kích hoạt Thuật bảo mệnh bát tinh Cổ Thần — cổ chi tí hữu, triệu hoán Cổ Thần hư ảo khổng lồ ôm mình bảo vệ, Cổ Thần tung quyền đánh Chưởng Tôn hoàn toàn trọng thương. Vương Lâm vung huyết kiếm tấn công bất thành, cầm kiếm bỏ chạy chuẩn bị Súc Địa thành thốn thì nghe Chưởng Tôn hứa có thể hồi sinh vợ con, toàn thân như sét đánh dừng bước, nhớ lại suy nghĩ về Tư Mã Mặc, nhận ra ngày phải lựa chọn giữa tự do và quy phục đã tới."},{"chuong":1341,"tieuDe":"Tình Và Ân","tomTat":"Chưởng Tôn dù trọng thương vẫn trực tiếp đánh vào điểm yếu lớn nhất đạo tâm Vương Lâm, hứa cầu sư tôn — người cùng tề danh Viễn Cổ Tiên Tôn thời Thái Cổ — tìm sinh linh giới, giết hàng vạn người lấy hồn phách hóa Trường sinh ấn hồi sinh cả Lý Mộ Uyển và Vương Bình. Đề nghị ban ngoại hiệu Lâm Thương Tử, địa vị vượt Tư Mặc Tử, Thanh Thủy, Thanh Lâm. Vương Lâm rơi vào đấu tranh nội tâm kịch liệt nhất đời, lần lượt hồi tưởng ân tình Tư Đồ Nam, Thanh Thủy, Chu Dật, lão Thánh Hoàng, Chu Tước đời hai, lão tổ Luyện Hồn Tông. Ký ức Tư Mặc Tử — kẻ vì muội muội mà từ bỏ tất cả trở thành nô bộc Chưởng Tôn — trở thành tấm gương cảnh tỉnh. Vương Lâm kiên định từ chối, tuyên bố đời không chỉ có tình mà còn có ân, khẳng định sẽ tự mình tái sinh thê tử. Xoay người hóa cầu vồng bay vào tinh không, hai hàng nước mắt rơi, thốt lời xin Uyển Nhi và Bình Nhi đừng trách."},{"chuong":1342,"tieuDe":"Hắn Có Phải Là Chưởng Tôn Không?","tomTat":"Vương Lâm trọng thương nặng sau cuộc chiến tại thánh địa Hỏa Tước tộc, vừa rời đi thì thánh địa sụp đổ, sóng xung kích lửa hủy diệt các bộ lạc xung quanh. Hắn thi triển Súc Địa Thành Thốn tới tu chân tinh bỏ hoang, ngồi bên bờ sông thổ nạp, thì thào nhớ Uyển Nhi và Bình Nhi, hứa sẽ cứu sống vợ rồi cả nhà ẩn cư sơn thôn. Hắn nhớ tới ngọc giản mà nữ tử thần bí từng đưa ở cái khe tầng chín Vân Hải Tinh vực — mở ở giới ngoại có thể tránh Phong Giới Đại Trận quay về, nhưng chưa dám mở vì trọng thương và chưa rõ bạn thù. Sau khi bình tĩnh, hắn phân tích nghi ngờ danh tính Chưởng Tôn: nam tử trung niên thi triển nhiều thần thông khớp nhưng không dùng bổn nguyên Thái Sơ Lực mà Thanh Lâm từng nói, khí chất cũng không giống kiêu hùng vạn năm. Ba ngày thổ nạp nhờ thân lục tinh Cổ Thần hồi phục năm phần, hắn nhận ra Điên Lạc đã bị phong ấn bên ngoài. Đột nhiên dự cảm nguy hiểm nổi lên, bầu trời nứt ra, một bàn tay khổng lồ vươn từ khe nứt chộp lấy hắn khi đang sắp dung nhập trời đất."},{"chuong":1343,"tieuDe":"Phụng Thiên Lang","tomTat":"Vương Lâm đang dung nhập thiên địa chạy trốn thì bị tiếng sói tru từ khe nứt trên bầu trời bức ra, lập tức bị bàn tay khổng lồ của tu sĩ Không Niết sơ kỳ thuộc Phụng Thiên lang tộc chộp tới. Hắn vung móng tay đen do Đại Hoang thượng nhân tặng, xuyên thấu phá hủy cánh tay đối phương và gây trúng độc, nhưng bản thân bị chấn thương phun máu. Dùng Cổ Tức Diệp phình to ngàn trượng phong ấn khe nứt rồi thoát ra Thái Cổ tinh thần, triệu hồi Cổ Tức Diệp bằng thuật Lạc diệp quy căn. Từ khe nứt bước ra đại hán ba trượng thuộc Phụng Thiên lang tộc — một trong tứ đại Thái Cổ hung tộc dưới trướng Chưởng Tôn — trên vai ngồi thiếu nữ áo đỏ mi tâm mang ấn ký Phong Diệt tộc, là thị nữ của Diệu Âm đạo tôn (Thái Cổ ngũ tôn), cầm la bàn định vị Vương Lâm. Nữ tử tiết lộ muốn lấy hết đồ vật trên người Vương Lâm, đổi lại đạo tôn thưởng lục phẩm đạo linh cho đại hán. Vương Lâm dùng Cổ Tức Diệp phong ấn hố đen lần hai ngăn truy kích, thoáng thấy ấn ký Phong Diệt tộc trên mi tâm nữ tử khiến tâm thần chấn động. Đại hán vòng đường khác tiếp tục truy kích hướng bộ lạc phân tông Phụng Thiên lang tộc, phía sau hiện con sói hư ảo xanh khổng lồ."},{"chuong":1344,"tieuDe":"Vương Lâm Phục Kích!","tomTat":"Vương Lâm đã tính toán trước lộ tuyến truy đuổi của đại hán Phụng Thiên Lang tộc, lưu lại phục kích sau khi thôn phệ khôi phục nguyên thần. Cách không vỗ một cái khiến sáu tu chân tinh đồng thời nổ tung, hình thành cơn lốc nuốt trọn đại hán. Thanh Lang vạn trượng lao ra từ cơn lốc cắn tới Vương Lâm, hắn triệu mai rùa Cổ Hồn cấm hóa cự quy khổng lồ chống đỡ, cả hai phản chấn — Thanh Lang sụp đổ, mai rùa thu nhỏ. Vương Lâm nhận ra ấn ký Phong Diệt tộc trên mi tâm thiếu nữ ngồi trên vai đại hán, đánh giá mối uy hiếp của nàng ngang bước ba Không Niết, quyết định ưu tiên giết nàng. Dùng hư hỏa làm mồi nhử buộc đại hán toàn lực áp chế, huyết kiếm giấu sẵn trong tu chân tinh bất ngờ lao ra xuyên thẳng mi tâm thiếu nữ rồi bay về, Vương Lâm dùng Súc địa thành thốn bỏ chạy hướng cổ mộ. Thiếu nữ Phong Diệt tộc sống lại nhờ đặc tính mệnh ba hồn, vết thương khép lại để sẹo vĩnh viễn, mất một mạng còn hai. Nàng dùng la bàn xác định Vương Lâm ở phía Đông Bắc hướng cổ mộ, cảnh giác lộ tuyến có thể là bẫy. Đại hán xé tinh không truy đuổi tiếp. Bên ngoài khe cổ mộ sương mù dày đặc, nhiều tu sĩ Thái Cổ Tinh Thần đứng ngoài, một luồng khí tức khiến cả thái cổ chấn động bộc phát từ sâu bên trong."},{"chuong":1345,"tieuDe":"Cổ Mộ Mở Ra","tomTat":"Khe cổ mộ tại Thái Cổ Tinh Thần nứt toác, tử khí và oán khí tích tụ vô tận năm tháng bùng nổ thành cuồng phong sương mù lan rộng mấy ngàn vạn dặm tinh không, tu sĩ bị cuốn vào mười người chết chín, người sống sót trẻ lại ngàn năm với ấn ký hình số trên mi tâm rồi bị hút vào trung tâm. Phân thân thiếu niên của Diệu Âm đạo tôn triệu hơn trăm triệu hương hỏa hồn bao thân xông vào sương mù, toàn bộ hương hỏa hồn bị hủy, tu vi suy từ Không Linh trung kỳ xuống Không Niết sơ kỳ và bị hút vào, ngộ ra sương mù giới hạn tu vi tối đa Không Niết sơ kỳ. Âm Dương lão nhân nhìn ra quy tắc, đẩy Vũ Đông Thiện và Cực Hiền Thiên từ mi tâm vào cơ thể Vọng Nguyệt, ra lệnh cả ba tiến vào cổ mộ rồi lui về tịnh tọa tái nhợt. Đại Hoang thượng nhân không có phân thân, bắt tu sĩ ném vào sương mù thử, bảy người chết, người thứ tám sống sót bị lão phóng nguyên thần đoạt xá thành công rồi theo thân xác hút vào cổ mộ. Vương Lâm xuất hiện trong tinh không, trước đó đã phân thần thức dung nhập vào Thiên Vận Tử tính ra hướng đi có lợi. Đại hán Phụng Thiên Lang tộc xé không bước ra tấn công Vương Lâm bằng Bát phương cực lang đạo, Vương Lâm hóa lưu tinh né tránh, cơn lốc sương mù đánh tan tám con sói rồi cuốn tới đại hán. Tu vi đại hán Không Niết sơ kỳ không suy yếu thêm, mi tâm xuất hiện ấn ký, nhưng nữ tử trên vai phát ra tiếng kêu thảm thiết."},{"chuong":1346,"tieuDe":"Âm Mưu Đáng Sợ!","tomTat":"Thiếu nữ Phong Diệt tộc bị sương mù vùng cổ mộ giết chết lần thứ hai, thân thể ăn mòn thành xương khô, nhưng sống lại nhờ mạng thứ ba, giờ chỉ còn duy nhất một mạng cuối cùng. Sương mù khắc ký hiệu con số lên mi tâm nàng rồi lực hút kéo nàng cùng đại hán Phụng Thiên Lang tộc vào sâu trong sương mù. Vương Lâm phát hiện sương mù nhập thể mình hóa thành sức mạnh Cổ Thần bị tinh điểm mi tâm hấp thụ nhưng chứa đầy tử khí và oán khí, quyết không hấp thụ. Hắn nhận ra ký hiệu con số trên mi tâm người khác chính là cổ văn, liên hệ với lời Tham Lang về phương hướng rời vùng đất cổ mộ, xác định hướng đi rồi kiên quyết tiến vào. Trên đường đi hắn hồi tưởng kế hoạch đối phó Chưởng Tôn bằng hồn phách Thiên Vận Tử, phát hiện một sức mạnh bí ẩn trong hư vô đã thao túng tâm trí mình suốt thời gian qua — ý tưởng tưởng tự phát thực ra bị can thiệp, sau khi vào sương mù thì sức mạnh đó bị ngăn trở và tiêu tan. Ở chỗ sâu nhất sương mù hắn gặp văn sĩ trung niên bí ẩn có chín pho tượng hộ thân xin giúp đỡ, nhưng không đáp, bước vào khe dữ tợn dẫn tới vùng đất cổ mộ. Trong một cung điện ẩn giấu giữa tinh không Thái Cổ Tinh Thần, kẻ mặc hắc bào đứng bên giếng nước tĩnh như gương dùng thuật Tĩnh Trung Lao Nguyệt phong ấn thân ảnh Vương Lâm bằng ba ngọn nến để thao túng hắn, nhưng khi Vương Lâm vào sương mù thì thân ảnh tiêu tan, kế hoạch thất bại."},{"chuong":1347,"tieuDe":"Tam Tỷ, Tứ Muội","tomTat":"Lão già hắc bào chuẩn bị giết Vương Lâm qua giếng nước trong đại điện nhưng bị lam quang bùng lên ngăn cản. Người trong lam quang tuyên bố sẽ ra tay nếu lão muốn giết Vương Lâm. Lão hắc bào nhắc ước định và thân phận Thái Cổ ngũ tôn của đối phương, người trong lam quang nhượng bộ cho Vương Lâm sống một lần. Bên ngoài khe cổ mộ, Vương Lâm phớt lờ lời nhờ giúp của văn sĩ trung niên (tam tỷ), nhận ra trong Thái Cổ Tinh Thần có sức mạnh mờ ám thao túng suy nghĩ mình, cảm thấy hãi hùng rồi tiến vào khe cổ mộ. Tam tỷ không thể dùng bản thể vào cổ mộ, kích hoạt chín pho tượng tạo phân thân nữ tử áo trắng cho vào thay. Tam tỷ tiết lộ cấu trúc nhóm chị em: đại tỷ và bát muội mất tích, nhị tỷ có đồng minh, tứ muội Hồ Mị Tử hợp tác Thác Sâm, ngũ muội đoạt xá được Lam Mộng đạo tôn giúp, thất muội phân thân bị Vương Lâm diệt. Hồ Mị Tử xuất hiện từ mi tâm Thác Sâm bằng thanh âm ma lực, giễu cợt tam tỷ từng là thánh nữ Thiên Đạo Môn bị Tiên Tôn bắt nuôi. Vương Lâm vào bên trong khe bị truyền tống, thi triển Quang Ảnh thuẫn phản kích kẻ đánh lén, quan sát không gian rộng lớn với đài cao đầu lâu trôi nổi và mấy trăm tu sĩ."},{"chuong":1348,"tieuDe":"Tình Ngữ, Sát Kiếp","tomTat":"Vương Lâm bước vào vùng đất cổ mộ bên trong cái khe mà không hề mê man, lập tức bị một nam tử trung niên tu vi thiên nhân đệ tam suy đánh lén, nhưng thần thông phản xạ ngược trúng chính kẻ tấn công. Vương Lâm thi triển Dịch Thiên Ấn một chiêu nghiền nát tu sĩ trung niên, lập uy trước mấy trăm tu sĩ. Hắn quan sát các đài cao trôi nổi có đầu lâu Cổ Thần với ấn ký mi tâm đã bị lấy đi, rồi bất ngờ gặp một nữ tử áo trắng dung nhan tuyệt trần, hình dáng cực kỳ giống văn sĩ trung niên bên ngoài khe. Khi ánh mắt hai người chạm nhau, toàn bộ cổ mộ kinh biến — bầu trời ầm ầm, sương mù cuộn cuồng, cái khe bên ngoài Thái Cổ Tinh Thần đóng chặt hoàn toàn. Lực phòng hộ của 99 đài cao đồng loạt tiêu tan, cột sương mù phóng lên giết chết tu sĩ, ấn ký con số trên mi tâm người chết bay ra biến thành ký hiệu trôi nổi. Quy tắc tàn khốc bộc lộ: hai tu sĩ cùng bước lên một đài cao thì sương mù ngàn trượng bùng phát hủy diệt cả đài, hơn 50 đài bị hủy theo cách này, chỉ còn 43 đài cho gần 200 tu sĩ. Vương Lâm nhanh trí chiếm một đài cao, phóng khí ngăn người khác vào, nhưng hơn mười tu sĩ mắt đỏ bừng lao tới liều chết tranh đoạt."},{"chuong":1349,"tieuDe":"Ba Người, Ba Người Lại Ba Người","tomTat":"Bốn mươi ba đài cao trong sương mù chỉ còn mỗi đài một tu sĩ chiếm giữ, mấy trăm tu sĩ không có chỗ chém giết điên cuồng tranh giành chỗ sống. Hơn mười tu sĩ xông vào đài cao của Vương Lâm, hắn dùng chưởng ấn lốc xoáy đánh lui quá nửa rồi liên tục giết sáu người bằng chỉ lực, chưởng đánh và kiếm khí, hút sương máu tử thi vào cơ thể, quát một tiếng tha ba người sống sót. Sương mù ngàn trượng bùng phát hủy diệt nhiều đài cao, từ 43 giảm còn 28, mấy trăm tu sĩ giảm còn chưa tới 80. Vương Lâm quan sát thấy thiếu nữ Phong Diệt tộc dùng hào quang mi tâm bảo vệ đài cao vững chắc, đồng thời chú ý năm cao thủ nổi bật: nữ tử áo trắng giết người bằng hắc khí độc không cần động tay, kiếm khách bầu rượu vừa ngâm thơ vừa dùng trường kiếm đâm mi tâm kẻ địch tạo hình hoa mai, nam tử áo tím triệu hồi cá dữ ngàn trượng nuốt người, và nam tử gầy áo đen nhắm mắt có tốc độ siêu phàm kéo nguyên thần giết người mà kể cả Vương Lâm cũng không nhìn rõ tung tích."},{"chuong":1350,"tieuDe":"Nghe Đồn Nghe Đồn Lại Nghe Đồn","tomTat":"Vòng tuyển chọn tàn khốc kết thúc, mấy trăm tu sĩ tử vong chỉ còn 28 người trên 28 đài cao, trong đó có bảy kẻ cướp đoạt đài thành công gồm lão già Thiên Nhân Tứ Suy và lão bà áo lục có thần thông mê mang. Vương Lâm khoanh chân thổ nạp chữa thương, cố tình ẩn giấu mọi thủ đoạn. Các tu sĩ xung quanh âm thầm đánh giá hắn nhưng không ai nhận ra thân phận hư hỏa, chỉ nữ tử Phong Diệt tộc biết. Vương Lâm thu pháp bảo cây quạt ba trượng Cổ Thần (nhận xét không phải tuyệt hảo). Bầu trời bỗng gầm thét, 28 đài cao chìm xuống vạn trượng vào biển sương mù, đưa mọi người đến ngoại vi vùng đất cổ mộ. Mãnh thú hình người toàn thân mụn mủ dày đặc mấy ngàn con tấn công từ sương mù, Vương Lâm nhận ra chúng giống vật kỳ dị từ đầu lâu Cổ Thần ở vùng đất Yêu Linh. Lão bà áo lục kêu gọi hợp tác, nói cần vượt khảo nghiệm mới được vào bên trong cổ mộ. Chương kết thúc bằng đoạn liệt kê những lời đồn đáng sợ về tu sĩ hư hỏa ở Thái Cổ Tinh Thần."},{"chuong":1351,"tieuDe":"Cơ Hội Trị Thương!","tomTat":"Mấy ngàn mãnh thú hình người từ sương mù xông ra tấn công hơn hai mươi lăm tu sĩ trên đài cao, tu vi cao nhất đạt Thiên Nhân đệ tam suy, khi bị giết sẽ tự bạo uy lực kinh người. Vương Lâm dùng kiếm khí chém giết mãnh thú và phát hiện nếu giết trước khi chúng tự bạo sẽ phóng ra bạch khí sức sống, hấp thụ vào cơ thể trị thương nhanh hơn cắn nuốt tu sĩ và có thể tăng tu vi. Hắn chủ động rời đài cao xông vào đàn mãnh thú, giết gần ngàn con, cứu nhiều tu sĩ bị bao vây tuyệt vọng trong đó có tu sĩ trung niên cầm bầu rượu. Nhiều tu sĩ tâm cơ thâm trầm nhận ra bí mật sức sống mãnh thú, hơn hai mươi người tranh nhau xông lên đòi chia phần ngàn con còn lại. Vương Lâm triệu Thiên Hoàng Lô từ tinh điểm Cổ Thần trên mi tâm, bao phủ và luyện hóa toàn bộ gần ngàn mãnh thú trước mặt mọi người, phát tu vi cường hãn chấn át bốn phương khiến không ai dám ra tay. Thiên Hoàng Lô thu về mi tâm bộc phát sức sống vô biên, thương thế Vương Lâm hồi phục cực nhanh. Hắn quyết định đã đến lúc lập uy, ngọn lửa hư ảo trong mắt trái bùng lên bốc cháy."},{"chuong":1352,"tieuDe":"Tu Sĩ Hư Hỏa!","tomTat":"Hơn hai mươi đài cao bị sức mạnh vô hình kéo bay qua biển sương mù trong cổ mộ với tốc độ ngang tu sĩ thiên nhân suy kiếp toàn lực, Vương Lâm đứng trên đài cao quan sát thận trọng và mơ hồ cảm giác trong sương có một cặp mắt đang nhìn tất cả. Nhóm 25 người tới một vùng đất bị phong ấn từ vô số năm, phạm vi hơn mười vạn trượng với bầu trời đỏ và sông ngòi đỏ như máu, trung tâm có Cổ Thần mấy ngàn trượng bị đánh nát đầu gối buộc phải quỳ cõng khối đài cao vỡ, hai bên có Cổ Ma và Cổ Yêu quỳ bái. Mặt đất chi chít mấy vạn mãnh thú hình người mắt đỏ đồng loạt tấn công, hai tu sĩ tu vi thấp bị xé xác. Hơn mười đại tu sĩ liên thủ đe dọa Vương Lâm không được cướp mãnh thú vì lần trước hắn đã nuốt hơn phân nửa. Vương Lâm không lui mà tăng tốc, chỉ vung tay phải khiến hư hỏa sinh bên trong cơ thể mãnh thú thiêu cháy hơn phân nửa mấy vạn con, sức sống tràn vào khôi phục thương thế hoàn toàn. Hắn xoay người hỏi ai muốn giết, mắt trái bùng hư hỏa chín màu, toàn trường nhận ra hắn là tu sĩ hư hỏa hiếm gặp mấy vạn năm một lần, kinh hoàng lui về sau."},{"chuong":1353,"tieuDe":"Địch Tới","tomTat":"Vương Lâm dùng uy thế hư hỏa lần lượt uy hiếp đám tu sĩ từng hỗn xược, buộc tu sĩ béo dâng mảnh lân giáp, tu sĩ hắc y dâng phi kiếm đen Cổ Ma, nam tử áo tím dâng hồ lô cổ mộ. Riêng bà lão áo lục không chịu khuất phục, Vương Lâm giao chiến trực tiếp, va chạm nguyên lực mấy mươi lần. Bà lão bị ép sử dụng Phong Huyễn Thuật — phun sương mù đỏ nhạt tạo ảo giác người chí thân để mê hoặc, bị nữ tử Phong Diệt Tộc nhận ra là thần thông của Phong Huyễn Tộc (tam đại kỳ tộc). Vương Lâm thi triển Tuế Nguyệt nhất chỉ dung nhập khí tức tang thương Phong Tiên Giới phá tan ảo giác, đánh bật phong ấn tâm tình, biến hư hỏa thành cấm chế trên người bà lão rồi tha mạng. Nữ tử tóc dài quá lưng không dâng pháp bảo, nở nụ cười rời đi qua khe hở bầu trời, để lại lời trong phong ấn có kỳ bảo và hẹn gặp lại. Đột nhiên thiên địa chấn động, chín đài cao khổng lồ từ chân trời ầm ầm lao tới, một giọng nói uy áp ra lệnh mọi người dâng pháp bảo cổ mộ rồi đợi xử lý."},{"chuong":1354,"tieuDe":"Nhị Giai Mộ Thai","tomTat":"Trong không gian phong ấn trên lưng Cổ Thần, chín tu sĩ cường giả đứng trên chín đài cao nhuộm đỏ máu, dẫn đầu bởi Linh Động Thượng Nhân — tu sĩ thân phận tôn quý ở Thái Cổ Tinh Thần, đã nửa bước vào bước thứ ba nhưng thiếu hương hỏa chưa đột phá. Linh Động sai một tu sĩ đi phá phong ấn sương mù đỏ, tu sĩ đó bị nuốt chửng mà chết, bản thân Linh Động thử cũng bị phản kích phải lùi hơn mười trượng. Lão già thanh bào tự xưng nghiên cứu thuật cấm chế ngàn năm, thi triển Vạn cấm phá quyết nhưng cũng bị sương mù nuốt chết. Hứa Phúc phản bội phe Vương Lâm, xưng thần với Linh Động Thượng Nhân, tuyên bố bảy phần nắm chắc phá cấm chế, toan tố cáo bí mật về Vương Lâm nhưng bị cắt lời. Vương Lâm lặng lẽ quan sát, nhận ra cấm chế là Cổ Hồn cấm và bên trong còn ẩn chứa cấm chế khác, đánh giá cao tâm cơ thâm trầm của văn sĩ trung niên Tiêu Tĩnh."},{"chuong":1355,"tieuDe":"Bọ Ngựa Rình Ve Sầu","tomTat":"Tu sĩ to béo họ Hứa dùng pháp bảo bàn tính phá cấm chế sương đỏ trên lưng Cổ Thần nhưng thất bại, pháp bảo bị hủy và bản thân bị sương đỏ nuốt tử vong. Vương Lâm quan sát, phân tích ra cấm chế trên sương đỏ gồm Cổ Hồn cấm và Tuế Nguyệt cấm kết hợp, đồng thời âm thầm ngưng tụ cấm chế dưới chân mà không ai hay biết. Văn sĩ trung niên Tiêu Tĩnh giả vờ phá cấm chế, dụ Linh Động Thượng Nhân dùng hương hỏa lực trợ giúp, khiến sương đỏ bùng nổ thành cơn lốc hủy diệt giết hơn mười tu sĩ, chỉ chưa tới mười người thoát qua khe nứt. Vương Lâm rút lui nhanh nhất, lao xuống dưới rồi bay lên trời. Nửa canh giờ sau, Tiêu Tĩnh bước ra từ sương đỏ, lộ mưu kế bọ ngựa rình ve sầu — lợi dụng sương đỏ bùng nổ đuổi tất cả để độc chiếm đạo linh. Hắn dùng chín ngọc giản khiến cấm chế ngừng vận hành hai mươi nhịp thở, xé khe trên sương đỏ nhưng trúng cấm chế bổ sung, thân thể thối rữa vỡ vụn — song đó chỉ là thi thể thế thân, bản thể phục hồi sau một nén nhang rồi tiếp tục tiến về phía sương đỏ."},{"chuong":1356,"tieuDe":"Ai Là Hoàng Tước","tomTat":"Văn sĩ trung niên Tiêu Tĩnh, biệt danh \"mưu hồ\" của Thái Cổ Tinh Thần, thi triển mưu kế tinh vi trong đám sương đỏ: giả chết hai lần, tổ hợp cấm chế kích động sương mù giết hơn nửa tu sĩ có mặt, phá hủy mọi lối vào vùng đất phong ấn để chiếm đoạt một mình. Tuy nhiên khi tiến sâu phá giải cấm chế, hắn bị Sinh Tử cấm giết chết — mặt và nguyên thần đều lộ nụ cười quỷ dị không thể kiểm soát cho đến khi tử vong hoàn toàn. Vương Lâm hiện thân từ trong cấm chế, hóa tro thi thể Tiêu Tĩnh rồi dựa vào kiến thức ba trong tứ đại cấm chế để phá Sinh Tử cấm, rút đường sống từ trong cái chết, mở ra thông đạo dẫn tới đài cao ngàn trượng. Linh Động Thượng Nhân lập tức xuất hiện chặn đường, nhốt Vương Lâm trong bọt khí, tự xưng là chim sẻ đứng sau bọ ngựa, thừa nhận đã lợi dụng cả Tiêu Tĩnh lẫn Vương Lâm phá cấm chế thay mình. Vương Lâm diễn kịch xuất sắc, giả vẻ đau khổ khuất phục, khéo léo dẫn dụ Linh Động tự tin bước vào thông đạo trước. Ngay khi Linh Động vào trong, tiếng kêu thảm thiết vang lên kèm câu \"vẫn còn cấm chế\", Vương Lâm ngẩng đầu lộ sát khí — hé lộ hắn mới là hoàng tước thật sự đứng sau tất cả, ba tầng mưu kế lồng nhau đều nằm trong tính toán của hắn."},{"chuong":1357,"tieuDe":"Thừa Dịp Giết Người!","tomTat":"Vương Lâm khai chiến với Linh Động Thượng Nhân trong thông đạo sương mù, lần lượt dùng huyết kiếm xuyên tay phải đối phương, lôi đình bổn nguyên phá pho tượng phòng thủ, hư hỏa chín màu đối kháng Sơn Hải Đồ. Lần đầu thi triển Lôi hỏa giao hòa — dung hợp lôi đình và hỏa diễm tại mi tâm phá nát ngọn núi, rồi kích hoạt hư hỏa bên trong cơ thể đối phương đốt cháy từ bên trong. Linh Động Thượng Nhân phản kích bằng Sơn Hải Đồ và triệu hồi Thủy Động Ma Thần từ Linh Động Đại Ma Giới bằng hương hỏa, nhưng Vương Lâm triệu Cổ Thần hư ảnh từ cánh tay phải, Cổ Thần lấy lưng che chở rồi một quyền phá nát pho tượng ma thần. Hai bên đều sở hữu Cổ Tức Diệp, hai lá phong ấn triệt tiêu lẫn nhau. Vương Lâm cách không rút ba ngọc giản của Tiêu Tĩnh ra khỏi sương mù, sương đỏ khôi phục khép lỗ hổng nhốt Linh Động Thượng Nhân cùng tứ phẩm hỏa đạo linh bên trong. Linh Động Thượng Nhân nửa thân thể còn lộ ngoài sương, Vương Lâm vung một chỉ Định khống chế."},{"chuong":1358,"tieuDe":"Bí Mật Của Ngôi Mộ","tomTat":"Vương Lâm thi triển Định Thân Thuật vào thời điểm Linh Động Thượng Nhân trọng thương cực điểm, sương đỏ nuốt đối phương vào bên trong, đánh cấm chế để đạo linh bị phong ấn bên trong tấn công, tiếng gào của Linh Động dần tiêu tan. Vương Lâm dùng lôi đình từ mắt phải tạo lưới sét, lửa từ mắt trái tạo biển lửa bao phủ, rồi kích hoạt tinh điểm Cổ Thần trên mi tâm triệu Thiên Hoàng Lô ra bao phủ toàn bộ đám sương đỏ luyện hóa Linh Động — lộ ra công năng thực sự của Thiên Hoàng Lô là pháp khí Cổ Thần chuyên luyện nô bộc. Vương Lâm tách hai Cổ Tức Diệp đang phong ấn lẫn nhau, ngạc nhiên phát hiện Linh Động cũng sở hữu một chiếc, dùng thần thức kết hợp sức mạnh Cổ Thần xóa dấu ấn thần thức Linh Động rồi thu hồi cả hai. Bước lên đài cao bậc hai cao hai ngàn trượng, Vương Lâm phát hiện bề mặt chứa 589 ký hiệu chính là dấu ấn con số từ mi tâm tu sĩ tử vong. Hắn thu hơn mười ký hiệu nạp vào đài cao, đến ký hiệu thứ 11 thì đài cao chấn động, hút bụi đất mở rộng lên ba ngàn trượng, đổi sắc từ đỏ sẫm sang tím trông như đại lục nhỏ. Ngay lập tức một khí tức dạng thần thức từ đài cao tràn ra qua hai chân vào cơ thể Vương Lâm, cưỡng chế hóa thành hình ảnh dung hợp với ký ức mà hắn hoàn toàn không thể phản kháng."},{"chuong":1359,"tieuDe":"Bí Mật Của Ngôi Mộ (2)","tomTat":"Vương Lâm nhắm mắt trên đài cao, trước mắt hiện ra bản đồ cổ mộ khổng lồ phần lớn bị sương đen che phủ, chỉ ba phần đã lộ, có con đường mơ hồ dẫn sâu vào bên trong. Hắn xác định vị trí hiện tại là Hỏa Đạo Phong Địa, một trong ba phong địa cùng loại trên bản đồ. Khi mở mắt phát hiện vùng đất phong ấn xuất hiện vô số khe nứt quỷ dị chỉ nhìn thấy khi đứng trên đài cao, nhận định đài cao là mấu chốt toàn bộ cổ mộ. Sau đó hắn ngồi bên ngoài Thiên Hoàng Lô dùng cấm chế đánh vào sương mù bên trong, sương mù co rút từ ngàn trượng xuống còn trăm trượng. Hắn dùng ba ngọc giản của văn sĩ trung niên ấn lên sương mù khiến nó đình chỉ, rồi dùng sức mạnh Cổ Thần tạo hai bàn tay hồn phách xé mở sương mù, lộ ra tứ phẩm đạo linh hình kỳ lân. Đạo linh lao ra tấn công nhưng bị Thiên Hoàng Lô chặn, phía sau nó là thi thể Linh Động Thượng Nhân bại trận máu thịt lẫn lộn nhưng nguyên thần vẫn sống. Vương Lâm thu đạo linh, tuyên bố muốn biến Linh Động Thượng Nhân thành Cô Nô bước thứ ba, dùng sáu tinh điểm Cổ Thần bắt đầu quá trình luyện nô tàn khốc."},{"chuong":1360,"tieuDe":"Ban Cho Tên Cổ Nô Tử","tomTat":"Linh Động Thượng Nhân tỉnh lại bên trong Thiên Hoàng Lô, tuyên bố đạo tâm mấy vạn năm không thể bị luyện hóa, tự tin sẽ phá lò thoát ra. Vương Lâm dùng sức mạnh Cổ Thần kích hoạt Thiên Hoàng Lô theo phương thức “Thiên Hoàng Vương Lộ, thập phủ luyện nô”, niệm ngôn ngữ Cổ Thần triệu hồi liên tiếp tám Cổ Thần toàn thân đỏ sẫm cầm búa chém liên hoàn. Linh Động triệu hồi pho tượng Ma Thần kháng cự, pho tượng chịu nhát búa đầu rồi tái sinh từ máu, nhưng trước tám búa liên hoàn cuối cùng vỡ vụn, dư lực xuyên thiên linh khiến Linh Động phun máu mê man. Vương Lâm nắm khoảnh khắc đó thi triển đạo thuật Mộng Đạo, xâm nhập ký ức cả đời Linh Động. Mộng cảnh cho thấy sư phụ Linh Động là thanh niên tên Vương Lâm, dẫn hắn vào Linh Động Tộc tu đạo dù hắn không phải người trong tộc. Sau đó một lão già áo đen bị trọng thương, tiết lộ tên thật cũng là Vương Lâm, trước khi chết trao tộc ấn Linh Động Tộc cho hắn. Ký ức cuối cho thấy Linh Động từng bị ba người truy kích gắt gao trong tinh không Thái Cổ Tinh Thần, tuyệt vọng suýt chết."},{"chuong":1361,"tieuDe":"Ban Cho Tên Cổ Nô Tử (2)","tomTat":"Vương Lâm dùng thuật Mộng Đạo kết hợp Thiên Hoàng Lô hoàn thành việc thu phục Linh Động Thượng Nhân. Hồi ức Linh Động lộ ra: cả đời nhiều lần gặp nguy sinh tử đều được người tự xưng Vương Lâm cứu mạng, cuối đời bị Thiên Nhân Đệ Ngũ Suy toàn thân rữa nát sắp chết, khi nhắm mắt gặp Vương Lâm đề nghị làm nô bộc đổi lấy đắc đạo, bị ban tên Cổ Nô Tử. Trong Thiên Hoàng Lô, tám thân ảnh Cổ Thần dung hợp thành Cổ Thần thứ chín giơ búa chém lần thứ mười, khắc ấn ký hình tròn trên mi tâm Linh Động, lão mất hết thần thái bị lốc hồn phách cuốn đi. Vương Lâm nhận định việc thu phục còn nhiều nhược điểm, cần thêm tế luyện và cấm chế. Sau đó Vương Lâm chuyển cảnh trong Thiên Hoàng Lô tới nơi phong ấn đạo linh giống kỳ lân, kinh ngạc trước tốc độ hồi phục thương thế cực nhanh của nó. Hắn triệu Thông Thiên Môn thi triển Lưu Nguyệt nghịch chuyển thời gian bóc từng lớp màn thần bí trên đạo linh, nhìn thấy bản chất thì biến sắc kinh hãi, thốt lên không thể nào."},{"chuong":1362,"tieuDe":"Câu Trả Lời!","tomTat":"Vương Lâm thi triển Lưu Nguyệt thuật lên tứ phẩm đạo linh, thời gian nghịch chuyển cực sâu khiến đạo linh lộ bản chất là đan dược to bằng đầu người, tiếp tục nghịch chuyển lộ ra tinh không cổ xưa hơn cả giới nội giới ngoại với chín mặt trời hỗn mang. Thân ảnh mơ hồ mặc đạo bào bảy màu, ngón trỏ phải đeo nhẫn xanh biếc, vung tay dung hợp chín mặt trời thành đan dược rồi nói mục đích là nuôi dưỡng thiên đạo và cần thêm biện pháp khác. Vương Lâm nhận ra người này trùng hình tượng pho tượng lấy từ Tham Lang nhưng pho tượng không có nhẫn, suy đoán có thể là Viễn Cổ Tiên Hoàng mà chưa xác nhận. Hắn suy tư bản chất thiên đạo, liên hệ máu thiên đạo Thiên Vận Tử mưu tính và Thanh Long Thánh Hoàng nuốt, nghĩ thiên đạo có thể giống pháp bảo hoặc mãnh thú như U Minh thú ở La Thiên. Dùng Thiên Hoàng Lô luyện hóa đạo linh ba ngày thu đan dược kim quang vạn trượng, không dám nuốt trực tiếp mà hút ngọn lửa tăng hỏa bổn nguyên, lôi đồ trong mắt phải bắt đầu thiêu đốt tạp chất, nhận ra lộ trình hư hỏa rồi đạo hỏa đại thành rồi lôi hỏa bổn nguyên đại thành. Đan dược chưa đủ linh động cần tế luyện. Cuối chương Vương Lâm chú ý những con sông đỏ như máu trên mặt đất rồi thả vô số Văn thú từ khe trữ vật."},{"chuong":1363,"tieuDe":"Đại Hoang Lão Độc","tomTat":"Vương Lâm triệu mười vạn Văn Thú do Hồng Vương dẫn đầu hấp thụ dòng sông máu trên mặt đất, thân thể chúng to gấp đôi, sức chiến đấu tăng mạnh. Hắn kiểm tra ba thi hài bộ tộc cổ đại đã hoàn toàn tử vong, hy vọng tìm thi thể Cổ Ma chưa chết hẳn để hoàn thành phân thân Cổ Ma. Thu đài cao ngàn trượng Cổ Thần vào trữ vật rồi rời vùng phong ấn, dẫn Văn Thú xuyên sương mù cổ mộ, dọc đường tiêu diệt mãnh thú hình người. Gặp hơn 30 tu sĩ đang tử chiến, Vương Lâm dùng Văn Thú giải cứu rồi uy hiếp đoạt đài cao bậc hai từ lão già Chu Công, rút 312 ấn ký dung nhập vào đài bậc ba, tổng hơn 900 ấn ký, gần đột phá bậc bốn. Vừa rời đi, một cánh tay vạn trượng khí tức Cổ Thần từ sương mù vươn ra chộp mất toàn bộ nhóm tu sĩ trong nháy mắt, Văn Thú hoảng sợ, Vương Lâm nhận ra sức mạnh không thể chống cự. Hắn tiếp tục hướng tới vùng phong ấn thứ hai, nơi phân hồn Đại Hoang Lão Độc và Diệu Âm đang giao chiến tranh đoạt tứ phẩm đạo linh, nữ tử Phong Diệt Tộc cũng tham chiến bên dưới. Diệu Âm chiếm ưu thế, khinh miệt phân hồn Đại Hoang, chê hắn tính cổ quái, trong Thái Cổ Tinh Thần ngoài Lão Điểu không có đạo hữu."},{"chuong":1364,"tieuDe":"Lạnh Lùng Nhìn Trời","tomTat":"Trong vùng đất phong ấn của cổ mộ, Đại Hoang Thượng Nhân và Diệu Âm Đạo Tôn giao chiến tranh đoạt tứ phẩm mộc đạo linh, cả hai bị cổ mộ áp chế tu vi chỉ còn Không Niết Sơ Kỳ. Vương Lâm cưỡi đài cao bậc ba dẫn mấy vạn Văn Thú đến, phái thần thức do thám phát hiện tu vi Diệu Âm bị áp chế, quyết định xông vào. Hắn dùng hư hỏa thiêu đốt đám tu sĩ cản đường, dùng lôi hỏa bổn nguyên dung hợp chống đỡ kiếm quang của Diệu Âm, mượn lực xông lên đặt cấm chế phong kín nữ tử Phong Diệt Tộc rồi thu vào trữ vật, toàn bộ quá trình sạch sẽ như nước chảy mây trôi. Diệu Âm dùng kế li gián, đề nghị trả đạo linh cho Đại Hoang để đổi lấy việc rời đi, mục đích thật là đoạt Thiên Nghịch trên người Vương Lâm. Đại Hoang giả vờ chấp nhận, lấy hương hỏa thề nhận đạo linh rồi bỏ đi, nhưng ngay lập tức quay lại tập kích Diệu Âm, tuyên bố lời thề vô dụng vì Vương Lâm là hậu bối của Cổ Thần Đồ Ti, bạn chí cốt cả đời hắn. Dưới sự hợp kích của cả hai, huyết kiếm Vương Lâm xuyên thấu lưng Diệu Âm trong khi năm móng tay Đại Hoang đánh vỡ thuẫn đâm vào trước ngực, khiến Diệu Âm trọng thương phun máu, buộc phải kích hoạt âm lãng diệt đạo phản đòn. Chương kết thúc khi Diệu Âm vẫn chưa hay biết đòn sát thủ mạnh nhất của Vương Lâm đã chuẩn bị xong."},{"chuong":1365,"tieuDe":"Chia Rẽ!","tomTat":"Diệu Âm Đạo Tôn hé lộ là một trong Thái Cổ Ngũ Tôn, đã dung hợp âm bổn nguyên đại thành và thủy bổn nguyên thành chính quả thành bước thứ ba Không Niết, phá thệ phù hương hỏa của Đại Hoang để phản kích. Đại Hoang phun máu do thệ phù bị phá, bổn tôn trên tinh cầu hoang dã cũng phun máu khiến toàn tinh cầu chết; phân hồn tung ngũ độc và giải ấn Đại Hoang Tam Tiên bốn vạn năm, ba châm hóa hắc quang tấn công mi tâm Diệu Âm. Diệu Âm mở Hải Dân Giới triệu biển tím hàng triệu sinh linh hương hỏa tấn công như đại hồng thủy, phá hủy thân thể phân hồn Đại Hoang, nhưng bị cái lưỡi tím đen quỷ dị biến toàn bộ biển thành biển độc, ba châm Tam Tiên cắm vào mi tâm, ngũ độc nhập thể. Tiếng biển gào thét giết gần trăm tu sĩ trên mặt đất, vùng đất phong ấn sụp đổ hoàn toàn. Vương Lâm chờ đúng thời cơ Diệu Âm trọng thương lùi lại, triệu Thiên Hoàng Lô chắn cuồng phong, Linh Động ẩn sẵn bên trong lao ra cùng pho tượng Ma Thần đánh trúng Diệu Âm, đẩy ba châm sâu thêm một tấc khiến độc bộc phát toàn diện, Diệu Âm trọng thương gần chết. Phân hồn Đại Hoang mất thân thể, lao tới muốn cưỡng bức đoạt xá nhập vào cơ thể Diệu Âm."},{"chuong":1366,"tieuDe":"Đòn Sát Thủ!","tomTat":"Linh Động vừa trở thành Cổ Nô Tử chưa lâu, chỉ ra tay được một kích rồi bị phản chấn phun máu, pho tượng sụp đổ, Vương Lâm thu hắn vào Thiên Hoàng Lô. Vương Lâm dù bị thương nặng vẫn gắng mở rộng Thiên Hoàng Lô mấy vạn trượng, cướp trước Đại Hoang Thượng Nhân thu toàn bộ độc hải vào trong, tính luyện thành giọt nước có sát thương chấn động bước thứ ba. Hắn cố ý không ấn hết ba cây châm vào mi tâm Diệu Âm để trì hoãn, tạo cơ hội cho phân hồn Đại Hoang hóa hắc khí chui vào thất khiếu Diệu Âm triển khai đoạt xá. Cánh tay khổng lồ mấy vạn trượng từ biển sương mù bất ngờ vươn ra, đánh trúng thân thể Diệu Âm khiến phun máu, Đại Hoang nhân đó áp chế nguyên thần đối phương đoạt xá thành công, rồi cả hai bị hút vào bàn tay. Vương Lâm trong lúc nguy cấp hiện chân thân Cổ Thần mấy trăm trượng, dùng hai Cổ Tức Diệp giữ khe hương hỏa Hải Dân Giới, hút bằng miệng được một thành rồi dùng Thiên Hoàng Lô hút thêm hai phần, tổng khoảng ba phần hương hỏa cho Linh Động hoàn thành bước thứ ba. Cuối cùng Vương Lâm bị cánh tay khổng lồ túm ngực kéo vào biển sương mù biến mất. Một canh giờ sau, đội tu sĩ hơn hai mươi người đi ngang qua không tìm thấy dấu vết chỗ phong ấn, nghi bản đồ sai rồi bỏ đi."},{"chuong":1367,"tieuDe":"Bàn Tay Khổng Lồ Tái Hiện!","tomTat":"Trong biển sương mù cổ mộ, bàn tay khổng lồ giáng xuống nghiêng nghiêng nắm lấy Vương Lâm và Đại Hoang Thượng Nhân cùng ba đài mộ. Vương Lâm nhận ra cánh tay hạ nghiêng chứ không thẳng, suy đoán bàn tay sẽ ném chứ không bắt giữ, ngăn Đại Hoang kích thích bàn tay. Đúng như dự đoán, bàn tay ném mạnh hai người như ném đá bay sâu vào cổ mộ với tốc độ cực nhanh. Vương Lâm thi triển phương pháp lấy lực chứng đạo của bộ tộc Huyền Vũ dậm mạnh vào bàn tay tạo phản lực, vượt qua Đại Hoang mà thoát ly. Đại Hoang Thượng Nhân bộc lộ nội tâm: ba lần bày sát cơ đều bị Vương Lâm hóa giải, vốn định thừa lúc suy yếu đầu độc chết nhưng không thành, buông ấn ký đã chuẩn bị sẵn rồi biến mất trong sương mù. Nửa ngày sau Vương Lâm dừng lại, phá hủy đài mộ Diệu Âm Đạo Tôn lấy ký hiệu cùng gần trăm ký hiệu thu từ tu sĩ tử vong, nâng đài mộ lên cấp năm (năm ngàn trượng, màu đen hoàn toàn). Bản đồ trong đầu mở thêm hai mảnh (tổng năm), vén gần nửa tấm màn cổ mộ. Phát hiện mình đã bị ném xuyên qua ba tấm bản đồ tới cuối tấm thứ năm, rời hẳn vùng đất cổ mộ bên ngoài, phía trước gần khu rừng Cổ Tức Diệp nơi Tham Lang từng lấy pho tượng bí ẩn."},{"chuong":1368,"tieuDe":"Ba Lần Sát Cơ","tomTat":"Trong mảnh bản đồ thứ sáu, Cửu Thiên ma tôn — một trong Thái Cổ Ngũ Tôn, từng bị trọng thương ở Điên Lạc — ngồi trên đài mộ sáu ngàn trượng có trận pháp đầu lâu, cảm ứng được đài mộ cấp năm mới xuất hiện. Đại hán Phụng Thiên Lang tộc ở mảnh bản đồ thứ tư cũng cảm ứng được, sắc mặt âm trầm. Nữ tử bạch y bí ẩn ở nơi sâu trong cổ mộ suy đoán đài mộ mới có lẽ là của Diệu Âm. Thác Sâm cùng nữ tử áo hồng quyến rũ tiến vào tầng sâu nhất cổ mộ, nơi dòng khí gào thét xé nát thân thể. Vương Lâm nhận thông điệp từ đài mộ cấp năm của Đạo Cổ Diệp Mịch: mở cấp năm thì mở cánh cửa luân hồi, đạt cấp chín thì lấy địa phủ rời đi, đồng thời cảm ứng bốn đài mộ cấp năm khác và nhận ra phải đoạt đài mộ để tiến lên. Vương Lâm dùng Cổ Tức Diệp mở lối vào khu rừng quỷ dị, phát hiện khu rừng có hình đầu lâu khi nhìn từ trên cao, dùng thần thức cảm nhận vật bí ẩn ẩn dưới đất rồi tung huyết kiếm chém xuống. Đại hán Phụng Thiên Lang tộc bước vào mảnh bản đồ thứ năm, cầm Cổ Tức Diệp đoạt được, nhắm tới cùng hướng với khu rừng."},{"chuong":1369,"tieuDe":"Thêm Một Cái?","tomTat":"Vương Lâm phóng huyết kiếm đánh xuống cánh rừng, lộ ra con mãnh thú giống Vọng Nguyệt — khối cầu thịt bốn xúc tu tím ẩn trong hốc mắt đầu lâu khổng lồ dưới đất. Hắn dùng lửa chín màu ở mắt trái thiêu cháy xúc tu, rồi phóng lôi đồ ở mắt phải tạo dòng xoáy lôi đình nghiền nát khối cầu thịt. Thổi bay bùn đất lộ ra nửa đầu lâu Cổ Thần cửu tinh có chín tinh điểm mờ — lần đầu tiên hắn thấy đầu lâu Cửu tinh Cổ Thần, nhận ra pho tượng bảy màu tồn tại chính để phong ấn nó. Hắn chui vào hốc mắt lấy ra một khúc xương lớn cỡ ba bàn tay, suy đoán Cổ Thần này bị giết trong thời Cổ Thần thất tổn thất kiếp. Từ đó hắn giả thiết đạo nhân bảy màu chính là viễn cổ tiên hoàng, đã có thiên đạo trước khi la bàn Thiên Nghịch bị cướp, vì nuôi đạo linh khó khăn nên sắp đặt mọi chuyện trong vùng đất cổ mộ. Hắn liên hệ lời Cổ Yêu Tháp Giả về nghịch tu đời thứ nhất, sứ giả thiên đạo Thiểm Lôi tộc gọi hắn là bộ tộc diệt đạo, Thanh Lâm nói thiên đạo đã chết — cuối cùng mê mang về bản chất thiên đạo và ai là bộ tộc diệt đạo đời đầu."},{"chuong":1370,"tieuDe":"Giả Thiết","tomTat":"Vương Lâm tiếp tục suy luận về Đạo Cổ, giả thiết vùng đất cổ mộ chính là Đạo Cổ, phân tích mục đích Tiên Hoàng ám hại tam tộc để nuôi thiên đạo, nhớ lại khi độ kiếp ở Liên Minh Tinh Vực từng mở khe thông đạo nhìn thấy vùng thiên địa kỳ dị, và nhớ lời Đạo Cổ Diệp Mịch về cửa luân hồi cùng địa phủ, cuối cùng thừa nhận suy đoán có thể sai. Hắn thiết lập sát trận phòng hộ quanh đầu lâu Cổ Thần bằng cấm chế, lôi đồ, lửa chín màu và huyết kiếm. Ngồi trên mi tâm đầu lâu dùng sức mạnh Cổ Thần sáu tinh điểm nuôi dưỡng đầu lâu và tập trung toàn lực vào mười chín cái cây khiến rễ dần khôi phục. Triệu Thiên Hoàng Lô luyện hóa biển độc đen từ lưỡi Đại Hoàng Thượng Nhân cùng hồn phách Diệu Âm Đạo Tôn, ba ngày sau biển giảm gần nửa, dự tính thu bảo vật mang độc. Phân nguyên thần vào Thiên Hoàng Lô kiểm tra Linh Động đang luyện hồn phách hương hỏa, truyền đạo thuật Dung qua lạc ấn vào mi tâm giúp hắn nhanh tiến bước thứ ba, tính toán dùng Linh Động phối hợp chiến đấu và nảy ý luyện thêm Cổ Nô. Bên ngoài, đại hán Phụng Thiên Lang tộc đứng trên đài cao bậc năm, còn ba ngày nữa tới mục tiêu chín chiếc lá, muốn phối hợp thần thông bản tộc khóa Phụng Thiên Lang Đạo vĩnh viễn bên người để trở thành Không Niết Sơ Kỳ mạnh nhất."},{"chuong":1371,"tieuDe":"Ban Thưởng Đạo","tomTat":"Linh Động lĩnh ngộ hoàn toàn đạo thuật Dung mà Vương Lâm ban cho, thi triển trong Thiên Hoàng Lô dung hợp bốn phần hồn phách hương hỏa, đột phá thành cao thủ bước thứ ba thực sự với hương hỏa hiện hình bên ngoài cơ thể. Vương Lâm lôi thiếu nữ Phong Diệt tộc Phong Chỉ Mạn ra thẩm vấn, cho xem ngọc giản cảnh phân thân Diệu Âm bị diệt để phá tan ảo tưởng, ép nàng khai bí mật Phong Diệt tộc: tộc nhân không huyết thống, cướp trẻ con tế tổ sống sót thì được tộc ấn và tam mệnh thuật ba mạng. Vương Lâm soát hồn Phong Chỉ Mạn, rút tộc ấn từ mi tâm nàng rồi thu giữ, dự định thả nàng sau khi rời cổ mộ. Vương Lâm nuôi dưỡng mười chín cái cây bằng sức mạnh Cổ Thần, ngộ ra dùng hơi thở khí tức Cổ Thần thổi vào mới phân biệt được lá thật, thu được mười tám chiếc Cổ Tức Diệp tỏa hào quang vạn trượng. Biển độc trong Thiên Hoàng Lô tiêu tan hóa thành chín giọt độc dịch cực mạnh. Trên bầu trời khu rừng, đài cao năm ngàn trượng xuất hiện với đại hán bí ẩn đứng trên, ngẩn ra khi thấy Vương Lâm."},{"chuong":1372,"tieuDe":"Bốn Niềm Vui","tomTat":"Vương Lâm khai chiến với đại hán Phụng Thiên Lang tộc Chu Cẩn ngay khi gặp mặt, lần lượt triệu hoán lôi đồ, lửa chín màu và huyết kiếm tấn công. Chu Cẩn triệu hoán Phụng Thiên Lang ngàn trượng chống trả, tuyên bố giết Vương Lâm sẽ nâng đài cao lên bậc sáu, đồng thời tham lam mười tám Cổ Tức Diệp. Vương Lâm ném Thiên Hoàng Lô gây phản chấn khiến Chu Cẩn phun máu, Linh Động ẩn bên trong xông ra lộ rõ đã tiến vào bước thứ ba thành công, triệu hoán pho tượng phối hợp tấn công. Vương Lâm dùng mười tám Cổ Tức Diệp phong ấn mọi phương vị chặn hết đường thoát. Chu Cẩn thi triển thần thông Quần Lang Bái Nguyệt triệu mười vạn sói và mặt trăng đỏ nhưng bị Thiên Hoàng Lô phóng to bao phủ thiên địa chặn đứng. Cuối cùng chín giọt nước màu đen xuất hiện khống chế hoàn toàn Chu Cẩn, Vương Lâm lạnh lùng tuyên bố cử động là chết."},{"chuong":1373,"tieuDe":"Chế Địch!","tomTat":"Vương Lâm dùng chín giọt độc dịch, Cổ Tức Diệp và Linh Động vây khốn Chu Cẩn hoàn toàn, sau đó ra lệnh thu hắn vào Thiên Hoàng Lô luyện hóa thành Cổ Nô, Linh Động bước vào bên trong trông coi. Vương Lâm thu Thiên Hoàng Lô vào mi tâm qua tinh điểm Cổ Thần, rồi dùng nhiều tầng cấm chế phong ấn khu rừng cây khô cùng vòng xoáy Tham Lang, triệu cánh cửa Lưu Nguyệt thêm tuế nguyệt cấm gia cố. Hấp thụ đài cao bậc năm của Chu Cẩn, đài cao tăng lên sáu ngàn trượng, nhận thông điệp Đạo Cổ Diệp Mịch tiết lộ về tam phủ Thiên Địa Nhân và Nhân Hỏa Kiếm — thanh kiếm tàn ác nhất thiên hạ bị ba đạo phong ấn. Vương Lâm bay từ bản đồ thứ năm vào thứ sáu, suy luận ra bản chất dấu ấn con số: là thứ cho phép tồn tại trong cổ mộ, Cổ Thần không cần. Cuối cùng dung hợp Cổ Thần lực, Cổ Ma lực và Cổ Yêu lực thành sức mạnh tam tộc vượt xa cả ba, xóa thành công dấu ấn con số trên mi tâm thiếu nữ Phong Diệt tộc, nhưng thiếu nữ lập tức bị sương mù cổ mộ sôi trào nuốt mất, biến mất trước mặt hắn."},{"chuong":1374,"tieuDe":"Phá Vỡ Quy Tắc","tomTat":"Vương Lâm thí nghiệm dung hợp khí tức tam tộc cổ (Cổ Thần lực, Cổ Ma lực, Cổ Yêu khí) trên mi tâm, phát hiện ấn ký dạng con số tự sinh ra rồi có thể lôi xuống mà không bị cổ mộ xóa sổ — vì bản thân là Cổ Thần nên vốn không cần ấn ký. Hắn ngộ ra bản chất quy tắc cổ mộ: ngoại nhân chỉ là sản phẩm thí luyện, ba tộc cổ mới là người thí luyện chính thức. Dùng phương pháp phá cách tự ngưng tụ hàng trăm ấn ký dung nhập đài mộ, thăng từ hơn cấp sáu lên cấp bảy rồi cấp tám — đài mộ cấp tám đầu tiên trong toàn cổ mộ, tiêu hao hết Cổ Yêu khí và phá hủy toàn bộ bảo vật Cổ Yêu. Lời nói lần thứ ba về Địa phủ hé lộ chủ nhân cả đời giết ba tiên tôn tù ấn bên trong, tam hồn cực kỳ cường đại. Cửu Thiên Ma Tôn ở bản đồ thứ tám cảm nhận có đối thủ, tự tin sẽ sớm đạt cấp tám bằng phân thân giết người. Nữ tử áo trắng cũng đạt đài mộ cấp bảy bằng bí thuật hấp thu ký hiệu rải rác. Thác Sâm ở bản đồ thứ chín đòi truyền thừa Diệp Mịch, trong khi nữ tử nổi bật phía sau lợi dụng hắn cảm ứng phương vị và hé lộ Địa phủ còn chứa một thứ ngoài tam tiên tôn khiến lão già kia cũng đỏ mắt."},{"chuong":1375,"tieuDe":"Gian Lận","tomTat":"Sương mù trong cổ mộ đột nhiên cuộn lên kịch liệt, quét sạch tu sĩ và mãnh thú ở nhiều tầng bản đồ, dấu ấn con số từ người chết bị tranh đoạt điên cuồng. Đại Hoang Thượng Nhân nhờ tranh đoạt dấu ấn mà nâng đài mộ lên cấp năm, cảm ứng được có đài mộ đã đạt cấp tám. Cửu Thiên Ma Tôn ở bản đồ thứ tám với đài mộ cấp bảy, chấn kinh khi phát hiện đài mộ cấp tám xuất hiện chưa đầy một ngày, chuyển hướng truy sát để cướp bí mật tăng cấp và nhắm tới địa phủ Đạo Cổ Diệp Mịch. Nữ tử áo trắng và nữ tử phong tình cũng đồng loạt đổi hướng, bốn phương cùng nhắm về Vương Lâm. Vương Lâm ngồi trên đài mộ cấp tám tám ngàn trượng, nghe thanh âm vạn cổ tang thương lần thứ tư tiết lộ bí mật Thiên Phủ trong tam phủ Thiên Địa Nhân — truyền thừa để tộc nhân thành đạo rời khỏi giới này tìm về quê hương bổn đạo. Nhận định pháp khí Cổ Yêu gần cạn, Vương Lâm tận dụng ưu thế cấp tám tránh né bốn kẻ truy kích, chạy vào bản đồ thứ bảy tìm vật Cổ Yêu. Khi Cửu Thiên Ma Tôn và nữ tử áo trắng tiến gần từ hai bên, Vương Lâm phản công bằng Phần Giới Cổ Tán — phun máu tươi khiến ô mờ hai phần, giải phóng lửa diệt thế bốn phương. Nữ tử áo trắng nhìn thấy rõ Vương Lâm thì sửng sốt."},{"chuong":1376,"tieuDe":"Người Nào Nhanh Hơn!","tomTat":"Vương Lâm thi triển Phần Giới Cổ Tán tạo biển lửa hủy diệt bức lui Cửu Thiên Ma Tôn và bạch y nữ tử, nương lực tấn công xuyên qua bản đồ thứ bảy tiến vào bản đồ thứ tám. Cửu Thiên Ma Tôn thi triển đạo thuật Cách Sơn Chi Tiên định giết Vương Lâm xuyên không gian, nhưng bạch y nữ tử (Tiên phi) quyết đoán mở Tinh môn chặn lại, hai bên đều bị chấn thương. Vương Lâm bay thẳng tới phong ấn Cổ Yêu trong bản đồ thứ tám, phát hiện Cổ Yêu vẫn còn sống, ít nhất bát tinh, đang đả tọa bị phong ấn giữ ngủ say trong cơn lốc xoáy mấy vạn trượng. Hắn nhảy vào cơn lốc, triệu Ma Hồn bình đánh nát ma hồn, thu khí tức Cổ Yêu, dung hợp ba khí tức (Cổ Yêu + Ma hồn + Cổ Thần lực) chế tạo ký hiệu nâng cấp đài mộ nhưng khoảng cách cấp chín còn rất xa. Nữ tử áo hồng (bát phi) từ bản đồ thứ chín tiến tới, dùng đạo thuật mê hoặc trong tiếng cười khiến Vương Lâm huyễn hóa ra Chu Tước và Liễu Mi, nhưng hắn nhanh chóng tỉnh táo nhờ đạo tâm hai ngàn năm. Cửu Thiên Ma Tôn, bạch y nữ tử và nữ tử áo hồng đều hội tụ về phong ấn Cổ Yêu, tình thế nguy cấp."},{"chuong":1377,"tieuDe":"Cổ Yêu Còn Sống","tomTat":"Vương Lâm ngồi trong vòng xoáy Cổ Yêu, dung hợp khí tức Cổ Yêu, Cổ Ma hồn từ Ma Hồn Bình và Cổ Thần lực từ tinh điểm mi tâm, tự chế tạo ký hiệu kỳ dị — điều mà Cửu Thiên Ma Tôn kinh ngạc cho rằng ngoài Thác Sâm không ai làm được. Ký hiệu nạp vào đài mộ tám ngàn trượng, đài mộ tăng trưởng lên chín ngàn trượng đạt cấp chín — đài mộ cấp chín đầu tiên trong cổ mộ. Đột ngột hai cánh tay khổng lồ từ hai đầu cổ mộ quét ngang toàn bộ chín tấm bản đồ, giết sạch mọi tu sĩ trên đường đi, phá vỡ vòng xoáy Cổ Yêu, đánh tan đài mộ cấp chín. Đại Hoang Thượng Nhân không kịp né bị cánh tay vỗ trực tiếp, cả thân thể lẫn phân hồn đều bị hủy — tử vong hoàn toàn. Cửu Thiên Ma Tôn đối kháng nhưng trọng thương, dung nhan biến từ lão già thành thiếu niên, toàn bộ phân thân trong cổ mộ tử vong để đổi đường sống. Phong ấn trên Cổ Yêu bị cánh tay nghiền nát, Cổ Yêu mở mắt thức tỉnh với tám tinh điểm xoay tròn trong mắt trái. Hai cánh tay vỗ vào nhau rồi tách ra xé hư vô mở một khe nứt lớn chứa thế giới kỳ dị, Vương Lâm không bị tổn thương nhưng tâm thần chấn động."},{"chuong":1378,"tieuDe":"Một Cái Vỗ Tay","tomTat":"Khe cổ mộ vốn đã biến mất trong Thái Cổ Tinh Thần đột ngột tái xuất, hút hơn phân nửa sương mù vào bên trong và không còn hạn chế tu vi người tiến vào. Đại Hoang Thượng Nhân phát hiện trước, trực tiếp nhảy vào cổ mộ. Diệu Âm Đạo Tôn rời tử hải nơi ẩn cư mấy vạn năm, thỏa thuận với Cửu Thiên Ma Tôn: Cửu Thiên giúp ngăn Đại Hoang, đổi lại Cửu Thiên lấy Vương Lâm. Người mặc áo đen xuất hiện dưới chưởng ấn hư ảo khổng lồ che lấp toàn tinh vực, cảnh báo đại chiến sắp tới nhưng cuối cùng để hai người vào, sau đó than nhẹ hé lộ Thái Cổ Ngũ Tôn gồm Đại Hoang, Chu Tọa, Viễn Cổ Tiên Tôn chiếm ba phần sức mạnh Thái Cổ Tinh Thần. Bên trong cổ mộ, hai bàn tay khổng lồ phá tan mộ đài cấp chín mở khe thông đến thế giới khác, Vương Lâm không do dự bước vào trong khi Cửu Thiên và Cổ Yêu không dám tiến lên. Cổ Yêu sau đó được giải phong ấn, mắt lộ hồng quang, ngửa mặt rít gào. Vương Lâm nghe di ngôn tang thương của Đạo Cổ Hoa Mịch về Thiên Phủ — nơi phong ấn kẻ địch, và quá khứ bị đạo sĩ Lý Quảng bắn rơi mắt trái chứa ký ức nửa đời. Vương Lâm tiến vào Thiên Phủ đại điện khổng lồ lộng lẫy nhưng âm u, phát hiện hàng ngàn tu sĩ đã chết đứng thẳng tắp biến thành đèn dầu, đài đá cao vút có ghế trống với quầng sáng bí ẩn và lỗ hổng chứa dấu tích kiếm xưa, bay lên cao chiếu sáng cung điện nhìn về phía xa thì đồng tử co rụt lại."},{"chuong":1379,"tieuDe":"Kịch Biến Trong Cổ Mộ","tomTat":"Vương Lâm bước vào đại điện khổng lồ trong cổ mộ, quan sát toàn cảnh chiến trường cổ xưa: mấy vạn tu sĩ hóa đá, tám đống thi thể cao như núi, tám con rồng hóa đá mấy vạn trượng, vô số chiến xa ngàn trượng, gần trăm thân ảnh và tám thân ảnh sánh ngang đại điện. Dưới lực dẫn dắt lần thứ năm từ mộ đài thăng cấp, hắn ngồi lên chiếc ghế khổng lồ trên đài, thân thể hóa thành Cổ Thần cao mấy trăm trượng, kích hoạt mười tám tinh điểm quỹ đạo đồng nhất ở mi tâm và hai mắt, tản mát uy nghiêm bá đạo vượt xa bước thứ ba. Uy áp bức Linh Động Thượng Nhân phải rời khỏi Thiên Hoàng Lô và quỳ phục hoàn toàn. Chu Cẩn nhân cơ hội phá ra khỏi Thiên Hoàng Lô, nhận ra sức mạnh là mượn từ ghế, kiên quyết chống cự nhưng khi uy áp bộc phát cực đại, đạo tâm tan nát, phun máu quỳ xuống khuất phục. Sau đó ánh mắt Vương Lâm nghịch chuyển thời gian, nhìn thấy ảo cảnh đại chiến cổ xưa, trong đó một văn sĩ trung niên cầm ô yên lặng xuyên qua đám tu sĩ đang xông lên, giơ tay chỉ về người ngồi trên ghế."},{"chuong":1380,"tieuDe":"Mượn Khí Thế!","tomTat":"Vương Lâm ngồi trên chiếc ghế tại đài cao trong cổ mộ, chứng kiến cảnh tượng hư ảo tái hiện trận chiến năm xưa của Đạo cổ Diệp Mịch. Hắn mượn khí thế hóa thân thành Diệp Mịch, tuần tự thi triển ba đạo thuật Thần chấn Binh Tu Liệt Vị, Yêu thuật Phong Hỏa Thành Sơn và Ma đạo Sinh Tử Nghịch Động tàn sát đại quân tấn công, rồi dung hợp sức mạnh ba tộc triệu hồi đầu lâu khổng lồ phun khí tức hủy diệt. Tuy nhiên tu sĩ áo đen Lý Quảng dùng cung chín phong ấn bắn rơi mắt trái Diệp Mịch, khiến chín tinh điểm Cổ Yêu trong mắt trái Vương Lâm vỡ tan và mắt trái chảy máu. Khi cảnh hư ảo tiêu tán, ý chí trong ghế thức tỉnh muốn thu hồi khí tức đã truyền, Vương Lâm kiên trì chống cự lực bài xích suốt mười bảy nhịp thở, đồng thời điểm ấn Cổ Nô lên Chu Cẩn, sai Linh Động và Chu Cẩn đứng hai bên chia sẻ lực phản chấn. Trong quá trình đấu tranh, Vương Lâm phát hiện cổ mộ có ba tầng, tầng ba chứa trái tim khổng lồ là nguồn truyền thừa hoàn chỉnh đạo cổ. Lực phản chấn ngày càng khủng khiếp khiến hai chân Vương Lâm tan nát, Linh Động mất tay trái và Chu Cẩn mất tay phải rồi cả hai bị đánh bật, nhưng tinh điểm Cổ Thần thứ bảy đã hình thành được một nửa. Thác Sâm theo cảm ứng tìm đến điên cuồng phá lưới định cướp truyền thừa, Vương Lâm dồn toàn bộ lực phản chấn vào thân thể Cổ Thần hóa đá ném thẳng vào Thác Sâm, đánh bật hắn bay ra dù cánh tay phải mình cũng tan nát."},{"chuong":1381,"tieuDe":"Truyền Thừa","tomTat":"Thác Sâm phá cấm chế xông vào cung điện, bị thi thể Cổ Thần đâm gãy tay phải nhưng vẫn cố xé lỗ hổng để đoạt truyền thừa. Vương Lâm chịu lực phản chấn nhịp thở thứ mười tám, thân thể tan vỡ hoàn toàn, trước khi tay trái nát đã triệu hai mươi lá cổ Tức Diệp phong ấn lỗ hổng và lệnh Linh Động, Chu Cẩn ngăn cản Thác Sâm. Linh Động triển khai tử hải hương hỏa, Chu Cẩn thi triển Quần Lang Bái Nguyệt, hai người Không Niết Sơ Kỳ hợp lực nhưng bị Thác Sâm phát tiếng rống Cổ Thần đánh bại, cuồng phong hủy diệt cung điện. Tinh điểm thứ bảy thực chất hóa bùng sáng, bảy tinh điểm xoay ba vòng tái tạo thân thể — Vương Lâm thành Vương tộc Thất tinh Cổ Thần, thân cao ngàn trượng. Vương Lâm tiếp nhận cảm ngộ chiêu Huyền Vũ lực đạo và thần thông truyền thừa từ chiếc ghế. Chiếc ghế hóa đài mộ, thần thức Vương Lâm được phóng đại vô số vạn lần dung hợp ý chí Đạo cổ Diệp Mịch lưu lại, tràn ra chấn nhiếp Thác Sâm. Nữ tử áo hồng trong tấm bản đồ thứ chín bị thần thức lướt qua, hoảng sợ tự hỏi Đạo cổ Diệp Mịch có phải vẫn chưa chết."},{"chuong":1382,"tieuDe":"Thất Tinh Cổ Thần","tomTat":"Vương Lâm ngồi trong cung điện cổ mộ, thần thức dung hợp ý chí cổ mộ khuếch tán quét qua toàn bộ tu sĩ bên trong, khiến phân thân Cửu Thiên Ma Tôn hoảng sợ, Đại Hoang Thượng Nhân cố bắt thần thức bị phản chấn, Diệu Âm Đạo Tôn tâm thần chấn động, nữ tử áo trắng sợ hãi xấu hổ. Thần thức lan tới khe cổ mộ thông ra Thái Cổ Tinh Thần, Vương Lâm phát hiện khe bị pháp lực bên ngoài làm đông cứng. Bên ngoài khe, Chưởng Tôn Thái Cổ Tinh Thần tự xưng danh, xin thả người. Vương Lâm dùng ý chí cổ mộ ép khe co lại, định phong ấn mấy vạn năm nhằm cắt đứt ba phần sức mạnh Thái Cổ Tinh Thần. Chưởng Tôn phản kích, thu chưởng ấn dung nhập tay phải vung một chưởng thái sơ lực xuyên khe đánh vào thần thức Vương Lâm. Từ tầng thứ ba cổ mộ phát ra tiếng rống của thần niệm Đạo Cổ Diệp Mịch, truyền qua ý chí cổ mộ vào thân thể Vương Lâm phát ra từ miệng hắn, gây sức hủy diệt kinh hoàng. Thác Sâm hơn nửa thân tan nát xác nhận là bát tinh Cổ Thần, phân thân Cửu Thiên Ma Tôn tan vỡ, tứ phi thân thể nổ tung dải lụa Viễn Cổ Tiên Tôn bị hủy, ba bổn tôn Không Huyền thân xác tan vỡ nguyên thần sống sót rút lui. Tiếng rống lao thẳng tới khe va chạm với chưởng ấn thái sơ lực của Chưởng Tôn."},{"chuong":1383,"tieuDe":"Sức Mạnh Của Một Tiếng Rống","tomTat":"Chưởng ấn của Chưởng Tôn tan vỡ không chút sức kháng cự trước tiếng rống từ bên trong khe nứt, khiến hắn phun máu, hai chân nổ tung chỉ còn xương trắng, hoảng sợ bỏ trốn mất tung tích — đây là lần thứ hai hắn bị tiếng rống đẩy lui. Nữ tử áo trắng bên trong cổ mộ bị tiếng rống trọng thương, gần tuyệt vọng khi khe sắp đóng, nhưng Vương Lâm dùng thần thức tạm dừng khe để nàng lao ra ngoài thoát thân, đáp lại ơn trước. Vương Lâm dùng ý chí cổ mộ triệt để phong ấn cổ mộ vạn vạn năm, thần thức dung hợp với ý chí cổ mộ khiến lực bài xích trên ghế hoàn toàn tiêu tan. Thác Sâm bị tiếng rống chấn thương nặng đang cấp tốc hồi phục, lộ ra tu vi hiện tại đạt bát tinh Cổ Thần nhờ chiếm thân thể Đồ Ti (vương tộc bát tinh tồn tại từ vạn cổ). Vương Lâm không ra tay với Thác Sâm đang trọng thương vì muốn đánh với Thác Sâm hoàn chỉnh, giữ tôn nghiêm Cổ Thần. Hắn dùng pho tượng thi thể Cổ Ma cao ngàn trượng bổ sung ma khí cho Cổ Ma tinh ở mắt phải nhưng chưa đủ. Nhận ra truyền thừa chỉ giúp đạt thất tinh, Vương Lâm dứt khoát cắt đứt dung hợp thần thức với cổ mộ để kích hoạt lại lực bài xích, với sức mạnh thất tinh trụ vững trên ghế, chủ động hấp thụ khí tức truyền thừa nhằm vượt qua thất tinh."},{"chuong":1384,"tieuDe":"Chủ Động","tomTat":"Sau hai ngàn năm tu đạo, thân thể Cổ Thần của Vương Lâm chính thức đạt thất tinh, đủ sức đối đầu tu sĩ Không Niết Sơ Kỳ bước thứ ba. Hắn ngồi trên ghế truyền thừa điên cuồng hấp thu khí tức, khiến mi tâm manh nha vòng xoáy tinh điểm thứ tám — mầm mống bát tinh Cổ Thần. Thác Sâm hồi phục tám phần, lần đầu tiên bỏ xưng hô bổn thần mà dùng ta, ngầm thừa nhận thân phận Cổ Thần của Vương Lâm, tuyên bố đây là trận chiến truyền thừa. Hai bên đối quyền, phía sau mỗi người đều hiện hư ảnh Đồ Ti — một bạo ngược, một tang thương — song quyền va chạm khiến cung điện nứt toác. Khi nữ tử phong tình thuộc viễn cổ bát phi tìm đến trợ chiến, Thác Sâm bất ngờ đánh bật nàng, mắng nàng là đồ chơi của Tiên Tôn rồi phong ấn tấm lưới cách ly hoàn toàn. Trong lúc hấp thu truyền thừa, mắt trái Vương Lâm chảy máu dữ dội vì khí tức không hoàn chỉnh do mắt trái Diệp Mịch năm xưa bị Lý Quảng bắn rơi, ký ức nửa đời về Mộ Uyển và cố hương bắt đầu bị xé rách biến mất. Đối mặt Diệt Thần Mâu — pháp khí vương tộc Đồ Ti — Vương Lâm hô Thần Chấn và Ma Đạo, dùng một ngón tay chạm thẳng mũi mâu, đồng thời tuôn thần thức xuyên qua lực phản chấn chiếc ghế tiến thẳng vào tầng thứ ba nơi có trái tim đang đập."},{"chuong":1385,"tieuDe":"Trận Chiến Định Mệnh Thứ 2","tomTat":"Vương Lâm mở mắt bạo phát Thần Chấn quyền kết hợp một chỉ ma đạo đối kháng Diệt Thần Mâu của Thác Sâm. Hắn cố ý dẫn lực phản chấn từ Diệt Thần Mâu đẩy thần thức chạm trái tim tầng thứ ba, khởi động truyền thừa thực sự — trái tim đồng bộ nhịp đập, ký ức hỗn độn ồ ạt nhập vào gây đau nhức kinh hoàng hơn cả tổn kiếp Cổ Thần. Hư ảnh Đồ Ti ở sau lưng tan vỡ, thay bằng cái đầu khổng lồ lờ mờ với mắt trái trống rỗng có máu đen. Vương Lâm dùng huyết kiếm kết hợp luồng đại lực truyền thừa chẻ đôi Diệt Thần Mâu như chẻ tre, xuyên thấu ngực Thác Sâm khiến hắn phun máu quỳ xuống đất. Vòng xoáy tinh điểm thứ tám trên mi tâm hoàn toàn ngưng tụ, tạo cơ sở đột phá bát tinh Cổ Thần tương lai. Thi thể Cổ Ma trên tay phải tan vỡ, giải phóng khối ma tinh thứ năm và thứ sáu. Mắt trái lờ mờ hơn phân nửa, ký ức sắp bị xóa — Vương Lâm không chấp nhận mất ký ức, chủ động đứng lên rời ghế cắt đứt truyền thừa tầng thứ ba, tuyên bố từ nay là Đạo Cổ chứ không còn là truyền thừa của Đồ Ti, rồi chủ động rút ký ức truyền thừa Đồ Ti ra khỏi hồn phách."},{"chuong":1386,"tieuDe":"Đạo Cổ Truyền Thừa","tomTat":"Vương Lâm chủ động hoá truyền thừa Đồ Ti thành hào quang trao cho Thác Sâm, vì truyền thừa chỉ đạt đỉnh bát tinh Cổ Thần, không còn tác dụng. Thác Sâm lần đầu trong đời nói hai chữ đa tạ. Vương Lâm thu Linh Động và Chu Cẩn vào Thiên Hoàng Lô, thu thi thể Cổ Ma, Cổ Tức Diệp, huyết kiếm. Hắn xé tấm lưới cấm chế phía bắc cung điện, tạo cuồng phong bắt Vũ Đông Thiện cùng đồng bạn, rồi thu Vọng Nguyệt vào khe không gian — nhớ rằng La Trần có ân vẫn ở trong cơ thể Vọng Nguyệt. Dùng ký ức Đạo Cổ truyền thừa duy nhất, Vương Lâm mở Địa Phù của Diệp Mịch trong bản đồ thứ chín — toà lầu các hoàng kim uy áp vô biên — thu vào trữ vật trước khi Diệu Âm, Cửu Thiên, Đại Hoang kịp đến. Hắn đánh ấn ký mở tầng cổ mộ thứ hai chứa chiến hồn làm lễ vật cho tu sĩ sống sót, rồi bước vào vòng xoáy thu luôn vùng đất phong ấn Cổ Tức Diệp khiến nó vĩnh viễn biến mất, khoá kín toàn bộ cổ mộ. Thác Sâm ở lại một mình trầm tư hoang mang về bản ngã — mình là Thác Sâm hay Đồ Ti — rồi quyết tâm đặt truyền thừa lên mi tâm. Vương Lâm mặc áo trắng xuất hiện tại giới nội ngoài biên giới La Thiên Tinh Vực, đúng chỗ Tham Lang bị cuốn năm xưa, phát khí thế kinh thiên. Lỗ Phu Tử bừng tỉnh từ nhập định, Vương Lâm mỉm cười nói về tới nhà rồi."}];
